pub const ScriptRuntime = struct {
    pub fn init() ScriptRuntime {
        return .{};
    }

    pub fn deinit(self: *ScriptRuntime) void {
        _ = self;
    }

    pub fn bootstrapInlineScripts(
        self: *ScriptRuntime,
        allocator: std.mem.Allocator,
        host: anytype,
    ) errors.Result(void) {
        var script_ids: std.ArrayList(dom.NodeId) = .empty;
        defer script_ids.deinit(allocator);

        const store = host.domStore();
        for (store.records()) |node| {
            const element = switch (node.kind) {
                .element => |element| element,
                else => continue,
            };

            if (std.mem.eql(u8, element.tag_name, "script")) {
                try script_ids.append(allocator, node.id);
            }
        }

        for (script_ids.items) |script_id| {
            const before_url = host.currentLocationUrl();
            {
                host.setCurrentScript(script_id);
                defer host.setCurrentScript(null);
                const source = try store.textContent(allocator, script_id);
                defer allocator.free(source);
                try self.evalScriptSourceWithBindings(allocator, host, source, "inline-script", &.{});
            }
            const after_url = host.currentLocationUrl();
            try self.dispatchHashChangeIfNeeded(allocator, host, before_url, after_url);
        }

        return;
    }

    pub fn dispatchHashChangeIfNeeded(
        self: *ScriptRuntime,
        allocator: std.mem.Allocator,
        host: anytype,
        before_url: []const u8,
        after_url: []const u8,
    ) errors.Result(void) {
        if (std.mem.eql(u8, urlFragmentText(before_url), urlFragmentText(after_url))) {
            return;
        }

        try self.dispatchWindowEvent(
            allocator,
            host,
            "hashchange",
            host.scriptEventListeners(),
            host.windowHashChange(),
            "onhashchange",
        );
        return;
    }

    pub fn dispatchWindowEvent(
        self: *ScriptRuntime,
        allocator: std.mem.Allocator,
        host: anytype,
        event_type: []const u8,
        listeners: []const ScriptListenerRecord,
        on_handler: ?ScriptFunction,
        handler_name: []const u8,
    ) errors.Result(void) {
        var event = ScriptEvent{
            .event_type = event_type,
            .target = .window,
            .current_target = null,
            .bubbles = false,
            .cancelable = false,
        };

        var matched_listeners: std.ArrayList(ScriptListenerRecord) = .empty;
        defer matched_listeners.deinit(allocator);

        for (listeners) |listener| {
            switch (listener.target) {
                .window => {},
                else => continue,
            }
            if (!std.mem.eql(u8, listener.event_type, event_type)) continue;
            try matched_listeners.append(allocator, listener);
        }

        for ([_]bool{ true, false }) |capture| {
            for (matched_listeners.items, 0..) |listener, index| {
                if (listener.capture != capture) continue;
                if (event.immediate_propagation_stopped) break;

                event.current_target = .window;
                event.phase = .at_target;

                var bindings = try eventListenerBindings(allocator, listener.handler, &event);
                defer bindings.deinit(allocator);

                const source_name = try std.fmt.allocPrint(allocator, "event:{s}:{d}", .{ event_type, index });
                defer allocator.free(source_name);

                try self.evalScriptSourceWithBindings(
                    allocator,
                    host,
                    listener.handler.body_source,
                    source_name,
                    bindings.items,
                );
            }
        }

        if (!event.immediate_propagation_stopped and !event.propagation_stopped) {
            if (on_handler) |handler| {
                event.current_target = .window;
                event.phase = .at_target;

                var bindings = try eventListenerBindings(allocator, handler, &event);
                defer bindings.deinit(allocator);

                const source_name = try std.fmt.allocPrint(allocator, "event:{s}:{s}", .{ event_type, handler_name });
                defer allocator.free(source_name);

                try self.evalScriptSourceWithBindings(
                    allocator,
                    host,
                    handler.body_source,
                    source_name,
                    bindings.items,
                );
            }
        }

        event.current_target = null;
        event.phase = .none;
        return;
    }

    pub fn dispatchDocumentEvent(
        self: *ScriptRuntime,
        allocator: std.mem.Allocator,
        host: anytype,
        event_type: []const u8,
        listeners: []const ScriptListenerRecord,
        on_handler: ?ScriptFunction,
        handler_name: []const u8,
    ) errors.Result(void) {
        var event = ScriptEvent{
            .event_type = event_type,
            .target = .document,
            .current_target = null,
            .bubbles = false,
            .cancelable = false,
        };

        var matched_listeners: std.ArrayList(ScriptListenerRecord) = .empty;
        defer matched_listeners.deinit(allocator);

        for (listeners) |listener| {
            switch (listener.target) {
                .document => {},
                else => continue,
            }
            if (!std.mem.eql(u8, listener.event_type, event_type)) continue;
            try matched_listeners.append(allocator, listener);
        }

        for ([_]bool{ true, false }) |capture| {
            for (matched_listeners.items, 0..) |listener, index| {
                if (listener.capture != capture) continue;
                if (event.immediate_propagation_stopped) break;

                event.current_target = .document;
                event.phase = .at_target;

                var bindings = try eventListenerBindings(allocator, listener.handler, &event);
                defer bindings.deinit(allocator);

                const source_name = try std.fmt.allocPrint(allocator, "event:{s}:{d}", .{ event_type, index });
                defer allocator.free(source_name);

                try self.evalScriptSourceWithBindings(
                    allocator,
                    host,
                    listener.handler.body_source,
                    source_name,
                    bindings.items,
                );
            }
        }

        if (!event.immediate_propagation_stopped and !event.propagation_stopped) {
            if (on_handler) |handler| {
                event.current_target = .document;
                event.phase = .at_target;

                var bindings = try eventListenerBindings(allocator, handler, &event);
                defer bindings.deinit(allocator);

                const source_name = try std.fmt.allocPrint(allocator, "event:{s}:{s}", .{ event_type, handler_name });
                defer allocator.free(source_name);

                try self.evalScriptSourceWithBindings(
                    allocator,
                    host,
                    handler.body_source,
                    source_name,
                    bindings.items,
                );
            }
        }

        event.current_target = null;
        event.phase = .none;
        return;
    }

    pub fn dispatchDomEvent(
        self: *ScriptRuntime,
        allocator: std.mem.Allocator,
        host: anytype,
        node_id: dom.NodeId,
        event_type: []const u8,
        bubbles: bool,
        cancelable: bool,
    ) errors.Result(DispatchOutcome) {
        return try self.dispatchDomEventWithMetadata(
            allocator,
            host,
            node_id,
            event_type,
            bubbles,
            cancelable,
            false,
            null,
            null,
            null,
            null,
        );
    }

    fn dispatchDomEventWithMetadata(
        self: *ScriptRuntime,
        allocator: std.mem.Allocator,
        host: anytype,
        node_id: dom.NodeId,
        event_type: []const u8,
        bubbles: bool,
        cancelable: bool,
        is_submit_event: bool,
        submitter_node: ?dom.NodeId,
        source_node: ?dom.NodeId,
        command_text: ?[]const u8,
        form_data: ?*FormDataState,
    ) errors.Result(DispatchOutcome) {
        const node = host.domStore().nodeAt(node_id) orelse return error.ScriptRuntime;
        switch (node.kind) {
            .element => {},
            else => return error.ScriptRuntime,
        }

        var event = ScriptEvent{
            .event_type = event_type,
            .target = .{ .element = node_id },
            .current_target = null,
            .bubbles = bubbles,
            .cancelable = cancelable,
            .is_submit_event = is_submit_event,
            .submitter_element = submitter_node,
            .source_element = source_node,
            .command_text = command_text,
            .form_data = form_data,
        };

        var ancestors: std.ArrayList(ListenerTarget) = .empty;
        defer ancestors.deinit(allocator);
        try domEventAncestorTargets(allocator, host, node_id, &ancestors);

        var index: usize = ancestors.items.len;
        while (index > 0) {
            index -= 1;
            try domEventRunListeners(self, allocator, host, ancestors.items[index], event_type, true, .capturing, &event);
            if (event.immediate_propagation_stopped or event.propagation_stopped) {
                event.current_target = null;
                event.phase = .none;
                return .{ .default_prevented = event.default_prevented };
            }
        }

        try domEventRunListeners(self, allocator, host, .{ .element = node_id }, event_type, true, .at_target, &event);
        if (event.immediate_propagation_stopped) {
            event.current_target = null;
            event.phase = .none;
            return .{ .default_prevented = event.default_prevented };
        }

        try domEventRunListeners(self, allocator, host, .{ .element = node_id }, event_type, false, .at_target, &event);
        if (event.immediate_propagation_stopped or event.propagation_stopped) {
            event.current_target = null;
            event.phase = .none;
            return .{ .default_prevented = event.default_prevented };
        }

        if (bubbles) {
            for (ancestors.items) |target| {
                try domEventRunListeners(self, allocator, host, target, event_type, false, .bubbling, &event);
                if (event.immediate_propagation_stopped or event.propagation_stopped) {
                    break;
                }
            }
        }

        event.current_target = null;
        event.phase = .none;
        return .{ .default_prevented = event.default_prevented };
    }

    pub fn dispatchCommandEvent(
        self: *ScriptRuntime,
        allocator: std.mem.Allocator,
        host: anytype,
        node_id: dom.NodeId,
        source_id: dom.NodeId,
        command_text: []const u8,
    ) errors.Result(DispatchOutcome) {
        return try self.dispatchDomEventWithMetadata(
            allocator,
            host,
            node_id,
            "command",
            false,
            true,
            false,
            null,
            source_id,
            command_text,
            null,
        );
    }

    pub fn dispatchSubmitEvent(
        self: *ScriptRuntime,
        allocator: std.mem.Allocator,
        host: anytype,
        node_id: dom.NodeId,
        submitter_node: ?dom.NodeId,
    ) errors.Result(DispatchOutcome) {
        const submit_outcome = try self.dispatchDomEventWithMetadata(
            allocator,
            host,
            node_id,
            "submit",
            true,
            true,
            true,
            submitter_node,
            null,
            null,
            null,
        );
        if (submit_outcome.default_prevented) return submit_outcome;

        const form_data_state = try formDataBuildState(allocator, host, node_id, submitter_node);
        _ = try self.dispatchDomEventWithMetadata(
            allocator,
            host,
            node_id,
            "formdata",
            true,
            false,
            false,
            null,
            null,
            null,
            form_data_state,
        );
        return submit_outcome;
    }

    pub fn evalScriptSourceWithBindings(
        self: *ScriptRuntime,
        allocator: std.mem.Allocator,
        host: anytype,
        source: []const u8,
        source_name: []const u8,
        bindings: []const Binding,
    ) errors.Result(void) {
        _ = self;
        return try executeScriptSource(allocator, host, source, source_name, bindings);
    }
};

const Program = struct {
    statements: []Statement,
};

const Statement = union(enum) {
    expression: *Expr,
    assignment: Assignment,
    const_declaration: ConstDeclaration,
};

const Assignment = struct {
    target: PropertyTarget,
    value: *Expr,
};

const ConstDeclaration = struct {
    name: []const u8,
    value: *Expr,
};

const PropertyTarget = struct {
    object: *Expr,
    property: []const u8,
};

const Expr = union(enum) {
    identifier: []const u8,
    string: []const u8,
    number: []const u8,
    boolean: bool,
    null_value,
    undefined_value,
    member: MemberExpr,
    call: CallExpr,
    new_expression: NewExpr,
    binary_add: BinaryAddExpr,
    arrow_function: ScriptFunction,
};

const MemberExpr = struct {
    object: *Expr,
    property: []const u8,
};

const CallExpr = struct {
    callee: *Expr,
    args: []*Expr,
};

const NewExpr = struct {
    callee: *Expr,
    args: []*Expr,
};

const BinaryAddExpr = struct {
    left: *Expr,
    right: *Expr,
};

const CollectionIteratorState = struct {
    items: []Value,
    index: usize = 0,
};

const IteratorResult = struct {
    value: Value,
    done: bool,
};

const CollectionEntry = struct {
    index: usize,
    value: Value,
};

const MediaQueryList = struct {
    host: ?*anyopaque = null,
    media: []const u8,
    matches: bool,
    current_matches_fn: ?*const fn (*anyopaque, []const u8) bool = null,
    get_onchange_fn: ?*const fn (*anyopaque, []const u8) ?ScriptFunction = null,
    set_onchange_fn: ?*const fn (*anyopaque, []const u8, ?ScriptFunction) errors.Result(void) = null,
    add_listener_fn: ?*const fn (*anyopaque, []const u8, ScriptFunction) errors.Result(void) = null,
    remove_listener_fn: ?*const fn (*anyopaque, []const u8, ScriptFunction) errors.Result(void) = null,

    fn currentMatches(self: *const MediaQueryList) bool {
        if (self.current_matches_fn) |current_matches_fn| {
            const host = self.host orelse return self.matches;
            return current_matches_fn(host, self.media);
        }
        return self.matches;
    }
};

const MediaListState = struct {
    host: ?*anyopaque = null,
    node_id: ?dom.NodeId = null,
    source_index: ?usize = null,
    media_text: []const u8,
    current_media_text_fn: ?*const fn (*anyopaque, *const MediaListState, std.mem.Allocator) errors.Result([]const u8) = null,
    set_media_text_fn: ?*const fn (*anyopaque, *MediaListState, []const u8, std.mem.Allocator) errors.Result(void) = null,

    fn currentText(self: *const MediaListState, allocator: std.mem.Allocator) errors.Result([]const u8) {
        if (self.current_media_text_fn) |current_media_text_fn| {
            const host = self.host orelse return error.ScriptRuntime;
            return try current_media_text_fn(host, self, allocator);
        }
        return self.media_text;
    }

    fn setText(self: *MediaListState, allocator: std.mem.Allocator, value: []const u8) errors.Result(void) {
        if (self.set_media_text_fn) |set_media_text_fn| {
            const host = self.host orelse return error.ScriptRuntime;
            try set_media_text_fn(host, self, value, allocator);
            self.media_text = try self.currentText(allocator);
            return;
        }
        return error.ScriptRuntime;
    }
};

const TimeRangesState = struct {};

const DateState = struct {
    timestamp_ms: f64,
};

const ValidityState = struct {
    node_id: dom.NodeId,
};

const StringListState = struct {
    items: []const []const u8,

    fn length(self: *const StringListState) usize {
        return self.items.len;
    }

    fn item(self: *const StringListState, index: usize) ?[]const u8 {
        if (index >= self.items.len) return null;
        return self.items[index];
    }

    fn contains(self: *const StringListState, value: []const u8) bool {
        for (self.items) |candidate| {
            if (std.mem.eql(u8, candidate, value)) {
                return true;
            }
        }
        return false;
    }
};

fn stringListIteratorValues(
    allocator: std.mem.Allocator,
    items: []const []const u8,
) errors.Result([]Value) {
    var values = try allocator.alloc(Value, items.len);
    errdefer allocator.free(values);

    for (items, 0..) |item, index| {
        values[index] = Value{ .string = item };
    }

    return values;
}

fn stringListKeys(
    allocator: std.mem.Allocator,
    items: []const []const u8,
) errors.Result(Value) {
    var values = try allocator.alloc(Value, items.len);
    errdefer allocator.free(values);

    for (items, 0..) |_, index| {
        values[index] = Value{ .number = @floatFromInt(index) };
    }

    return try collectionIteratorFromValues(allocator, values);
}

fn stringListValues(
    allocator: std.mem.Allocator,
    items: []const []const u8,
) errors.Result(Value) {
    return try collectionIteratorFromValues(allocator, try stringListIteratorValues(allocator, items));
}

fn stringListEntries(
    allocator: std.mem.Allocator,
    items: []const []const u8,
) errors.Result(Value) {
    const values = try stringListIteratorValues(allocator, items);
    defer allocator.free(values);
    return try collectionEntriesFromValues(allocator, values);
}

fn cssLayerStatementNameList(
    allocator: std.mem.Allocator,
    name_text: []const u8,
) errors.Result(StringListState) {
    var items: std.ArrayList([]const u8) = .empty;
    errdefer items.deinit(allocator);

    var parts = std.mem.splitScalar(u8, name_text, ',');
    while (parts.next()) |part| {
        const trimmed = std.mem.trim(u8, part, " \t\r\n\x0c");
        if (trimmed.len == 0) continue;
        try items.append(allocator, trimmed);
    }

    return .{ .items = try items.toOwnedSlice(allocator) };
}

fn tokenListIteratorValues(
    allocator: std.mem.Allocator,
    items: []const []const u8,
) errors.Result([]Value) {
    var values = try allocator.alloc(Value, items.len);
    errdefer allocator.free(values);

    for (items, 0..) |item, index| {
        values[index] = Value{ .string = item };
    }

    return values;
}

fn tokenListKeys(
    allocator: std.mem.Allocator,
    items: []const []const u8,
) errors.Result(Value) {
    var values = try allocator.alloc(Value, items.len);
    errdefer allocator.free(values);

    for (items, 0..) |_, index| {
        values[index] = Value{ .number = @floatFromInt(index) };
    }

    return try collectionIteratorFromValues(allocator, values);
}

fn tokenListValues(
    allocator: std.mem.Allocator,
    items: []const []const u8,
) errors.Result(Value) {
    return try collectionIteratorFromValues(allocator, try tokenListIteratorValues(allocator, items));
}

fn tokenListEntries(
    allocator: std.mem.Allocator,
    items: []const []const u8,
) errors.Result(Value) {
    const values = try tokenListIteratorValues(allocator, items);
    defer allocator.free(values);
    return try collectionEntriesFromValues(allocator, values);
}

fn tokenListForEach(
    allocator: std.mem.Allocator,
    host: anytype,
    bindings: []const Binding,
    items: []const []const u8,
    list_value: Value,
    args: []*Expr,
    source_prefix: []const u8,
) errors.Result(Value) {
    const callback_expr: *Expr = switch (args.len) {
        1, 2 => args[0],
        else => return error.ScriptRuntime,
    };
    const this_arg_expr: ?*Expr = if (args.len == 2) args[1] else null;

    const callback_value = try evalExpr(allocator, host, bindings, callback_expr);
    const callback = switch (callback_value) {
        .function => |function| function,
        else => return error.ScriptRuntime,
    };

    if (this_arg_expr) |expr| {
        _ = try evalExpr(allocator, host, bindings, expr);
    }

    for (items, 0..) |item, index| {
        const positional = [_]Value{
            .{ .string = item },
            .{ .number = @floatFromInt(index) },
            list_value,
        };
        var function_bindings = try functionBindings(allocator, callback, positional[0..]);
        defer function_bindings.deinit(allocator);

        const source_name = try std.fmt.allocPrint(allocator, "{s}:{d}", .{ source_prefix, index });
        defer allocator.free(source_name);

        try executeScriptSource(
            allocator,
            host,
            callback.body_source,
            source_name,
            function_bindings.items,
        );
    }

    return Value{ .undefined_value = {} };
}

fn emptyCollectionIterator(allocator: std.mem.Allocator) errors.Result(Value) {
    const items = try allocator.alloc(Value, 0);
    return try collectionIteratorFromValues(allocator, items);
}

fn emptyCollectionEntries(allocator: std.mem.Allocator) errors.Result(Value) {
    const items = try allocator.alloc(Value, 0);
    defer allocator.free(items);
    return try collectionEntriesFromValues(allocator, items);
}

fn namedNodeMapKeys(
    allocator: std.mem.Allocator,
    host: anytype,
    element: dom.NodeId,
) errors.Result(Value) {
    const items = try namedNodeMapCurrentValues(allocator, host, element);
    defer allocator.free(items);

    const keys = try allocator.alloc(Value, items.len);
    errdefer allocator.free(keys);

    for (keys, 0..) |*key, index| {
        key.* = Value{ .number = @floatFromInt(index) };
    }

    return try collectionIteratorFromValues(allocator, keys);
}

fn namedNodeMapValues(
    allocator: std.mem.Allocator,
    host: anytype,
    element: dom.NodeId,
) errors.Result(Value) {
    const items = try namedNodeMapCurrentValues(allocator, host, element);
    return try collectionIteratorFromValues(allocator, items);
}

fn namedNodeMapEntries(
    allocator: std.mem.Allocator,
    host: anytype,
    element: dom.NodeId,
) errors.Result(Value) {
    const items = try namedNodeMapCurrentValues(allocator, host, element);
    defer allocator.free(items);
    return try collectionEntriesFromValues(allocator, items);
}

fn namedNodeMapForEach(
    allocator: std.mem.Allocator,
    host: anytype,
    bindings: []const Binding,
    element: dom.NodeId,
    args: []*Expr,
) errors.Result(Value) {
    const callback_expr: *Expr = switch (args.len) {
        1, 2 => args[0],
        else => return error.ScriptRuntime,
    };
    const this_arg_expr: ?*Expr = if (args.len == 2) args[1] else null;

    const callback_value = try evalExpr(allocator, host, bindings, callback_expr);
    const callback = switch (callback_value) {
        .function => |function| function,
        else => return error.ScriptRuntime,
    };

    if (this_arg_expr) |expr| {
        _ = try evalExpr(allocator, host, bindings, expr);
    }

    const items = try namedNodeMapCurrentValues(allocator, host, element);
    defer allocator.free(items);

    for (items, 0..) |item, index| {
        const positional = [_]Value{
            item,
            .{ .number = @floatFromInt(index) },
            .{ .named_node_map = .{ .element = element } },
        };
        var function_bindings = try functionBindings(allocator, callback, positional[0..]);
        defer function_bindings.deinit(allocator);

        const source_name = try std.fmt.allocPrint(allocator, "namednodemap:forEach:{d}", .{index});
        defer allocator.free(source_name);

        try executeScriptSource(
            allocator,
            host,
            callback.body_source,
            source_name,
            function_bindings.items,
        );
    }

    return Value{ .undefined_value = {} };
}

