    target: StorageTarget,
    length_fn: *const fn (*anyopaque, StorageTarget) usize,
    get_item_fn: *const fn (*anyopaque, StorageTarget, []const u8) ?[]const u8,
    set_item_fn: *const fn (*anyopaque, StorageTarget, []const u8, []const u8) errors.Result(void),
    remove_item_fn: *const fn (*anyopaque, StorageTarget, []const u8) errors.Result(void),
    clear_fn: *const fn (*anyopaque, StorageTarget) errors.Result(void),
    key_fn: *const fn (*anyopaque, StorageTarget, usize) ?[]const u8,

    fn length(self: *const StorageState) usize {
        return self.length_fn(self.host, self.target);
    }

    fn getItem(self: *const StorageState, storage_key: []const u8) ?[]const u8 {
        return self.get_item_fn(self.host, self.target, storage_key);
    }

    fn setItem(self: *StorageState, storage_key: []const u8, value: []const u8) errors.Result(void) {
        return self.set_item_fn(self.host, self.target, storage_key, value);
    }

    fn removeItem(self: *StorageState, storage_key: []const u8) errors.Result(void) {
        return self.remove_item_fn(self.host, self.target, storage_key);
    }

    fn clear(self: *StorageState) errors.Result(void) {
        return self.clear_fn(self.host, self.target);
    }

    fn key(self: *const StorageState, index: usize) ?[]const u8 {
        return self.key_fn(self.host, self.target, index);
    }
};

const StylePropertyEntry = struct {
    name: []const u8,
    value: []const u8,
    important: bool = false,
};

const StyleValueEntry = struct {
    value: []const u8,
    important: bool,
};

const CssRuleStyleDeclarationKind = enum { style, page, font_face };

const StyleDeclarationState = struct {
    host: *anyopaque,
    element: dom.NodeId,
    get_attribute_fn: *const fn (*anyopaque, dom.NodeId, []const u8, std.mem.Allocator) errors.Result(?[]const u8),
    set_attribute_fn: *const fn (*anyopaque, dom.NodeId, []const u8, []const u8, std.mem.Allocator) errors.Result(void),
};

const AttributeState = struct {
    namespace_uri: ?[]const u8,
    name: []const u8,
    value: []const u8,
    owner_element: ?dom.NodeId,
};

const CssRuleStyleDeclarationState = struct {
    host: *anyopaque,
    kind: CssRuleStyleDeclarationKind,
    css_text: []const u8,
    parent_style_sheet: ?dom.NodeId = null,
    source_index: ?usize = null,
    writable: bool = false,
};

const CssRuleStyleDeclarationLiveState = struct {
    prefix_text: []const u8,
    selector_text: []const u8,
    css_text: []const u8,
};

fn cssRuleStyleDeclarationLiveState(
    allocator: std.mem.Allocator,
    host: anytype,
    state: *CssRuleStyleDeclarationState,
) errors.Result(?CssRuleStyleDeclarationLiveState) {
    const sheet_id = state.parent_style_sheet orelse return null;
    const source_index = state.source_index orelse return null;
    const current_rules = try cssRuleListCurrentValues(allocator, host, .{ .sheet = sheet_id });
    defer allocator.free(current_rules);
    if (source_index >= current_rules.len) return null;

    const current_rule = current_rules[source_index];
    if (current_rule != .css_rule) return null;
    return switch (current_rule.css_rule) {
        .style => |current_style| switch (state.kind) {
            .style => CssRuleStyleDeclarationLiveState{
                .prefix_text = "",
                .selector_text = current_style.selector_text,
                .css_text = try cssRuleStyleDeclarationText(current_style.css_text),
            },
            .page => null,
            .font_face => null,
        },
        .page => |current_page| switch (state.kind) {
            .page => CssRuleStyleDeclarationLiveState{
                .prefix_text = "@page ",
                .selector_text = current_page.selector_text,
                .css_text = try cssRuleStyleDeclarationText(current_page.css_text),
            },
            .style => null,
            .font_face => null,
        },
        .font_face => |current_font_face| switch (state.kind) {
            .font_face => CssRuleStyleDeclarationLiveState{
                .prefix_text = "@font-face",
                .selector_text = "",
                .css_text = try cssRuleStyleDeclarationText(current_font_face.css_text),
            },
            .style => null,
            .page => null,
        },
        else => null,
    };
}

fn cssRuleStyleDeclarationApply(
    allocator: std.mem.Allocator,
    host: anytype,
    state: *CssRuleStyleDeclarationState,
    css_text: []const u8,
) errors.Result(void) {
    if (!state.writable) return error.ScriptRuntime;
    const live = try cssRuleStyleDeclarationLiveState(allocator, host, state) orelse return error.ScriptRuntime;
    const sheet_id = state.parent_style_sheet orelse return error.ScriptRuntime;
    const source_index = state.source_index orelse return error.ScriptRuntime;

    var rule_text: std.ArrayList(u8) = .empty;
    defer rule_text.deinit(allocator);
    try rule_text.appendSlice(allocator, live.prefix_text);
    try rule_text.appendSlice(allocator, live.selector_text);
    try rule_text.appendSlice(allocator, " { ");
    try rule_text.appendSlice(allocator, css_text);
    try rule_text.appendSlice(allocator, " }");

    const parsed_rules = try parseStyleSheetRuleValues(allocator, rule_text.items);
    defer allocator.free(parsed_rules);
    if (parsed_rules.len != 1) return error.ScriptRuntime;
    if (parsed_rules[0] != .css_rule) return error.ScriptRuntime;
    switch (state.kind) {
        .style => if (parsed_rules[0].css_rule != .style) return error.ScriptRuntime,
        .page => if (parsed_rules[0].css_rule != .page) return error.ScriptRuntime,
        .font_face => if (parsed_rules[0].css_rule != .font_face) return error.ScriptRuntime,
    }

    const current_rules = try cssRuleListCurrentValues(allocator, host, .{ .sheet = sheet_id });
    defer allocator.free(current_rules);

    try styleSheetReplaceParsedRule(
        allocator,
        host,
        sheet_id,
        current_rules,
        parsed_rules[0],
        source_index,
    );
    return;
}

fn mediaListCurrentTextForRule(
    allocator: std.mem.Allocator,
    host: anytype,
    state: *const MediaListState,
) errors.Result([]const u8) {
    const sheet_id = state.node_id orelse return error.ScriptRuntime;
    const source_index = state.source_index orelse return error.ScriptRuntime;
    const current_rules = try cssRuleListCurrentValues(allocator, host, .{ .sheet = sheet_id });
    defer allocator.free(current_rules);
    if (source_index >= current_rules.len) return error.ScriptRuntime;

    const current_rule = current_rules[source_index];
    if (current_rule != .css_rule) return error.ScriptRuntime;
    return switch (current_rule.css_rule) {
        .media => |media| try allocator.dupe(u8, media.condition_text),
        else => error.ScriptRuntime,
    };
}

fn mediaListSetTextForRule(
    allocator: std.mem.Allocator,
    host: anytype,
    state: *MediaListState,
    value: []const u8,
) errors.Result(void) {
    const sheet_id = state.node_id orelse return error.ScriptRuntime;
    const source_index = state.source_index orelse return error.ScriptRuntime;
    const current_rules = try cssRuleListCurrentValues(allocator, host, .{ .sheet = sheet_id });
    defer allocator.free(current_rules);
    if (source_index >= current_rules.len) return error.ScriptRuntime;

    const current_rule = current_rules[source_index];
    if (current_rule != .css_rule) return error.ScriptRuntime;
    const media_rule = switch (current_rule.css_rule) {
        .media => |media| media,
        else => return error.ScriptRuntime,
    };

    const body_text = std.mem.trim(u8, try cssRuleStyleDeclarationText(media_rule.css_text), " \t\r\n\x0c");
    var rule_text: std.ArrayList(u8) = .empty;
    defer rule_text.deinit(allocator);
    try rule_text.appendSlice(allocator, "@media ");
    try rule_text.appendSlice(allocator, value);
    try rule_text.appendSlice(allocator, " { ");
    try rule_text.appendSlice(allocator, body_text);
    try rule_text.appendSlice(allocator, " }");

    const parsed_rules = try parseStyleSheetRuleValues(allocator, rule_text.items);
    defer allocator.free(parsed_rules);
    if (parsed_rules.len != 1) return error.ScriptRuntime;
    if (parsed_rules[0] != .css_rule) return error.ScriptRuntime;
    if (parsed_rules[0].css_rule != .media) return error.ScriptRuntime;

    try styleSheetReplaceParsedRule(
        allocator,
        host,
        sheet_id,
        current_rules,
        parsed_rules[0],
        source_index,
    );
    return;
}

const DomRectState = struct {
    x: f64,
    y: f64,
    width: f64,
