fn urlFragmentText(url: []const u8) []const u8 {
    const fragment_index = std.mem.indexOfScalar(u8, url, '#') orelse return "";
    if (fragment_index + 1 >= url.len) return "";
    return url[fragment_index + 1 ..];
}

