        .import => |import_rule| import_rule.parent_style_sheet,
        .namespace => |namespace_rule| namespace_rule.parent_style_sheet,
    };
}

fn cssRuleParentRule(rule: CssRuleState) ?*const CssRuleState {
    return switch (rule) {
