        .property => |property_rule| property_rule.parent_rule,
        .charset => |charset_rule| charset_rule.parent_rule,
        .import => |import_rule| import_rule.parent_rule,
        .namespace => |namespace_rule| namespace_rule.parent_rule,
    };
}

fn cssRuleCssText(rule: Value) []const u8 {
    return switch (rule) {
        .css_rule => |state| switch (state) {
            .style => |style| style.css_text,
            .media => |media| media.css_text,
            .supports => |supports| supports.css_text,
            .supports_condition => |supports_condition| supports_condition.css_text,
            .document => |document| document.css_text,
            .container => |container| container.css_text,
            .starting_style => |starting_style| starting_style.css_text,
            .keyframes => |keyframes| keyframes.css_text,
            .keyframe => |keyframe| keyframe.css_text,
            .font_face => |font_face| font_face.css_text,
            .font_feature_values => |font_feature_values| font_feature_values.css_text,
            .font_palette_values => |font_palette_values| font_palette_values.css_text,
            .color_profile => |color_profile| color_profile.css_text,
            .scope => |scope| scope.css_text,
            .page => |page| page.css_text,
            .position_try => |position_try| position_try.css_text,
            .layer => |layer| layer.css_text,
            .counter_style => |counter_style| counter_style.css_text,
            .property => |property_rule| property_rule.css_text,
            .charset => |charset_rule| charset_rule.css_text,
            .import => |import_rule| import_rule.css_text,
            .namespace => |namespace_rule| namespace_rule.css_text,
        },
        else => unreachable,
    };
}

fn cssRuleType(rule: CssRuleState) usize {
    return switch (rule) {
        .style => 1,
        .charset => 2,
        .import => 3,
        .media => 4,
        .font_face => 5,
        .page => 6,
        .keyframes => 7,
        .keyframe => 8,
        .namespace => 10,
        .counter_style => 11,
        .supports => 12,
        .font_feature_values => 14,
        else => 0,
    };
}

fn cssRuleListKeys(
    allocator: std.mem.Allocator,
    host: anytype,
    list: CssRuleListState,
) errors.Result(Value) {
    const rules = try cssRuleListCurrentValues(allocator, host, list);
    defer allocator.free(rules);
    var items = try allocator.alloc(Value, rules.len);
    errdefer allocator.free(items);
    for (rules, 0..) |_, index| {
        items[index] = Value{ .number = @floatFromInt(index) };
    }
    return try collectionIteratorFromValues(allocator, items);
}

fn cssRuleListValues(
    allocator: std.mem.Allocator,
    host: anytype,
    list: CssRuleListState,
) errors.Result(Value) {
    const rules = try cssRuleListCurrentValues(allocator, host, list);
    return try collectionIteratorFromValues(allocator, rules);
}

fn cssRuleListEntries(
    allocator: std.mem.Allocator,
    host: anytype,
    list: CssRuleListState,
) errors.Result(Value) {
    const rules = try cssRuleListCurrentValues(allocator, host, list);
    defer allocator.free(rules);
    return try collectionEntriesFromValues(allocator, rules);
}

fn cssRuleListForEach(
    allocator: std.mem.Allocator,
    host: anytype,
    bindings: []const Binding,
    list: CssRuleListState,
    args: []*Expr,
) errors.Result(Value) {
    const callback_expr: *Expr = switch (args.len) {
        1, 2 => args[0],
        else => return error.ScriptRuntime,
    };
    const this_arg_expr: ?*Expr = if (args.len == 2) args[1] else null;

    const callback_value = try evalExpr(allocator, host, bindings, callback_expr);
    const callback = switch (callback_value) {
        .function => |function| function,
        else => return error.ScriptRuntime,
    };

    if (this_arg_expr) |expr| {
        _ = try evalExpr(allocator, host, bindings, expr);
    }

    const rules = try cssRuleListCurrentValues(allocator, host, list);
    defer allocator.free(rules);

    for (rules, 0..) |rule, index| {
        const positional = [_]Value{
            rule,
            .{ .number = @floatFromInt(index) },
            .{ .css_rule_list = list },
        };
        var function_bindings = try functionBindings(allocator, callback, positional[0..]);
        defer function_bindings.deinit(allocator);

        const source_name = try std.fmt.allocPrint(allocator, "cssrulelist:forEach:{d}", .{index});
        defer allocator.free(source_name);

        try executeScriptSource(
            allocator,
            host,
            callback.body_source,
            source_name,
            function_bindings.items,
        );
    }

    return Value{ .undefined_value = {} };
}

fn styleSheetInsertRule(
    allocator: std.mem.Allocator,
    host: anytype,
    bindings: []const Binding,
    sheet_id: dom.NodeId,
    args: []*Expr,
) errors.Result(Value) {
    if (args.len != 1 and args.len != 2) return error.ScriptRuntime;

    const tag_name = host.domStore().tagNameForNode(sheet_id) orelse return error.ScriptRuntime;
    if (!std.mem.eql(u8, tag_name, "style")) return error.ScriptRuntime;

    const rule_text_value = try evalExpr(allocator, host, bindings, args[0]);
    const rule_text = try asString(allocator, rule_text_value);

    const current_rules = try cssRuleListCurrentValues(allocator, host, .{ .sheet = sheet_id });
    defer allocator.free(current_rules);

    const parsed_rules = try parseStyleSheetRuleValues(allocator, rule_text);
    defer allocator.free(parsed_rules);
    if (parsed_rules.len != 1) return error.ScriptRuntime;

    const index = if (args.len == 2) index_value_blk: {
        const index_value = try evalExpr(allocator, host, bindings, args[1]);
        break :index_value_blk try asNodeListIndex(index_value);
    } else 0;
    return try styleSheetInsertParsedRule(
        allocator,
        host,
        sheet_id,
        current_rules,
        parsed_rules[0],
        index,
    );
}

fn styleSheetAddRule(
    allocator: std.mem.Allocator,
    host: anytype,
    bindings: []const Binding,
    sheet_id: dom.NodeId,
    args: []*Expr,
) errors.Result(Value) {
    if (args.len != 2 and args.len != 3) return error.ScriptRuntime;

    const tag_name = host.domStore().tagNameForNode(sheet_id) orelse return error.ScriptRuntime;
    if (!std.mem.eql(u8, tag_name, "style")) return error.ScriptRuntime;

    const selector_value = try evalExpr(allocator, host, bindings, args[0]);
    const selector = try asString(allocator, selector_value);
    const style_value = try evalExpr(allocator, host, bindings, args[1]);
    const style_text = try asString(allocator, style_value);

    const current_rules = try cssRuleListCurrentValues(allocator, host, .{ .sheet = sheet_id });
    defer allocator.free(current_rules);

    const index = if (args.len == 3) index_value_blk: {
        const index_value = try evalExpr(allocator, host, bindings, args[2]);
        break :index_value_blk try asNodeListIndex(index_value);
    } else current_rules.len;

    var rule_text: std.ArrayList(u8) = .empty;
    defer rule_text.deinit(allocator);
    try rule_text.appendSlice(allocator, selector);
    try rule_text.appendSlice(allocator, " { ");
    try rule_text.appendSlice(allocator, style_text);
    try rule_text.appendSlice(allocator, " }");

    const parsed_rules = try parseStyleSheetRuleValues(allocator, rule_text.items);
    defer allocator.free(parsed_rules);
    if (parsed_rules.len != 1) return error.ScriptRuntime;

    return try styleSheetInsertParsedRule(
        allocator,
        host,
        sheet_id,
        current_rules,
        parsed_rules[0],
        index,
    );
}

fn styleSheetInsertParsedRule(
    allocator: std.mem.Allocator,
    host: anytype,
    sheet_id: dom.NodeId,
    current_rules: []const Value,
    inserted_rule: Value,
    index: usize,
) errors.Result(Value) {
    if (index > current_rules.len) return error.ScriptRuntime;

    var serialized: std.ArrayList(u8) = .empty;
    defer serialized.deinit(allocator);

    var wrote_any = false;
    for (current_rules, 0..) |rule, current_index| {
        if (current_index == index) {
            if (wrote_any) try serialized.append(allocator, '\n');
            try serialized.appendSlice(allocator, cssRuleCssText(inserted_rule));
            wrote_any = true;
        }

        if (wrote_any) try serialized.append(allocator, '\n');
        try serialized.appendSlice(allocator, cssRuleCssText(rule));
        wrote_any = true;
    }

    if (index == current_rules.len) {
        if (wrote_any) try serialized.append(allocator, '\n');
        try serialized.appendSlice(allocator, cssRuleCssText(inserted_rule));
    }

    host.domStoreMut().setTextContent(sheet_id, serialized.items) catch |err| switch (err) {
        error.OutOfMemory => return error.OutOfMemory,
        else => return error.ScriptRuntime,
    };
    return Value{ .number = @floatFromInt(index) };
}

fn styleSheetDeleteRule(
    allocator: std.mem.Allocator,
    host: anytype,
    bindings: []const Binding,
    sheet_id: dom.NodeId,
    args: []*Expr,
) errors.Result(Value) {
    if (args.len != 1) return error.ScriptRuntime;

    const tag_name = host.domStore().tagNameForNode(sheet_id) orelse return error.ScriptRuntime;
    if (!std.mem.eql(u8, tag_name, "style")) return error.ScriptRuntime;

    const index_value = try evalExpr(allocator, host, bindings, args[0]);
    const index = try asNodeListIndex(index_value);

    const current_rules = try cssRuleListCurrentValues(allocator, host, .{ .sheet = sheet_id });
    defer allocator.free(current_rules);
    if (index >= current_rules.len) return error.ScriptRuntime;

    var serialized: std.ArrayList(u8) = .empty;
    defer serialized.deinit(allocator);

    var wrote_any = false;
    for (current_rules, 0..) |rule, current_index| {
        if (current_index == index) continue;
        if (wrote_any) try serialized.append(allocator, '\n');
        try serialized.appendSlice(allocator, cssRuleCssText(rule));
        wrote_any = true;
    }

    host.domStoreMut().setTextContent(sheet_id, serialized.items) catch |err| switch (err) {
        error.OutOfMemory => return error.OutOfMemory,
        else => return error.ScriptRuntime,
    };
    return Value{ .undefined_value = {} };
}

fn styleSheetReplaceSync(
    allocator: std.mem.Allocator,
    host: anytype,
    bindings: []const Binding,
    sheet_id: dom.NodeId,
    args: []*Expr,
) errors.Result(Value) {
    if (args.len != 1) return error.ScriptRuntime;

    const tag_name = host.domStore().tagNameForNode(sheet_id) orelse return error.ScriptRuntime;
    if (!std.mem.eql(u8, tag_name, "style")) return error.ScriptRuntime;

    const css_text_value = try evalExpr(allocator, host, bindings, args[0]);
    const css_text = try asString(allocator, css_text_value);

    const parsed_rules = try parseStyleSheetRuleValues(allocator, css_text);
    defer allocator.free(parsed_rules);

    var serialized: std.ArrayList(u8) = .empty;
    defer serialized.deinit(allocator);

    for (parsed_rules, 0..) |rule, index| {
        if (index != 0) try serialized.append(allocator, '\n');
        try serialized.appendSlice(allocator, cssRuleCssText(rule));
    }

    host.domStoreMut().setTextContent(sheet_id, serialized.items) catch |err| switch (err) {
        error.OutOfMemory => return error.OutOfMemory,
        else => return error.ScriptRuntime,
    };
    return Value{ .undefined_value = {} };
}

fn parseStyleSheetRuleValues(
    allocator: std.mem.Allocator,
    source: []const u8,
) errors.Result([]Value) {
    var rules: std.ArrayList(Value) = .empty;
    errdefer rules.deinit(allocator);

    var pos: usize = 0;
    while (true) {
        pos = try skipCssTrivia(source, pos);
        if (pos >= source.len) break;
        try rules.append(allocator, try parseStyleSheetRuleValue(allocator, source, &pos));
    }

    return try allocator.dupe(Value, rules.items);
}

fn parseStyleSheetRuleValue(
    allocator: std.mem.Allocator,
    source: []const u8,
    pos: *usize,
) errors.Result(Value) {
    if (source[pos.*] == '@') {
        return try parseStyleSheetAtRuleValue(allocator, source, pos);
    }
    return try parseStyleSheetQualifiedRuleValue(allocator, source, pos);
}

fn parseStyleSheetQualifiedRuleValue(
    allocator: std.mem.Allocator,
    source: []const u8,
    pos: *usize,
) errors.Result(Value) {
    _ = allocator;
    const selector_start = pos.*;
    const block_start = try parseCssRuleBlockStart(source, pos.*);
    const selector_text = std.mem.trim(u8, source[selector_start..block_start], " \t\r\n\x0c");
    if (selector_text.len == 0) return error.ScriptRuntime;

    const block_end = try parseCssRuleBlockEnd(source, block_start + 1);
    const css_text = std.mem.trim(u8, source[selector_start..block_end], " \t\r\n\x0c");
    pos.* = block_end;

    return Value{ .css_rule = .{
        .style = .{
            .selector_text = selector_text,
            .css_text = css_text,
        },
    } };
}

fn parseStyleSheetAtRuleValue(
    allocator: std.mem.Allocator,
    source: []const u8,
    pos: *usize,
) errors.Result(Value) {
    const at_start = pos.*;
    pos.* += 1;

    const keyword_start = pos.*;
    while (pos.* < source.len and (isIdentifierContinueByte(source[pos.*]) or source[pos.*] == '-')) {
        pos.* += 1;
    }
    if (keyword_start == pos.*) return error.ScriptRuntime;

    const keyword = source[keyword_start..pos.*];
    if (std.ascii.eqlIgnoreCase(keyword, "charset")) {
        return try parseStyleSheetCharsetRuleValue(allocator, source, at_start, pos);
    }
    if (std.ascii.eqlIgnoreCase(keyword, "import")) {
        return try parseStyleSheetImportRuleValue(allocator, source, at_start, pos);
    }
    if (std.ascii.eqlIgnoreCase(keyword, "namespace")) {
        return try parseStyleSheetNamespaceRuleValue(allocator, source, at_start, pos);
    }
    if (std.ascii.eqlIgnoreCase(keyword, "layer")) {
        return try parseStyleSheetLayerRuleValue(allocator, source, at_start, pos);
    }
    if (std.ascii.eqlIgnoreCase(keyword, "property")) {
        return try parseStyleSheetPropertyRuleValue(allocator, source, at_start, pos);
    }
    if (std.ascii.eqlIgnoreCase(keyword, "scope")) {
        return try parseStyleSheetScopeRuleValue(allocator, source, at_start, pos);
    }
    if (std.ascii.eqlIgnoreCase(keyword, "color-profile")) {
        return try parseStyleSheetColorProfileRuleValue(allocator, source, at_start, pos);
    }

    const rule_kind = if (std.ascii.eqlIgnoreCase(keyword, "media"))
        CssBlockAtRuleKind.media
    else if (std.ascii.eqlIgnoreCase(keyword, "supports"))
        CssBlockAtRuleKind.supports
    else if (std.ascii.eqlIgnoreCase(keyword, "supports-condition"))
        CssBlockAtRuleKind.supports_condition
    else if (std.ascii.eqlIgnoreCase(keyword, "document"))
        CssBlockAtRuleKind.document
    else if (std.ascii.eqlIgnoreCase(keyword, "container"))
        CssBlockAtRuleKind.container
    else if (std.ascii.eqlIgnoreCase(keyword, "starting-style"))
        CssBlockAtRuleKind.starting_style
    else if (std.ascii.eqlIgnoreCase(keyword, "position-try"))
        CssBlockAtRuleKind.position_try
    else if (std.ascii.eqlIgnoreCase(keyword, "keyframes"))
        CssBlockAtRuleKind.keyframes
    else if (std.ascii.eqlIgnoreCase(keyword, "font-face"))
        CssBlockAtRuleKind.font_face
    else if (std.ascii.eqlIgnoreCase(keyword, "font-feature-values"))
        CssBlockAtRuleKind.font_feature_values
    else if (std.ascii.eqlIgnoreCase(keyword, "font-palette-values"))
        CssBlockAtRuleKind.font_palette_values
    else if (std.ascii.eqlIgnoreCase(keyword, "page"))
        CssBlockAtRuleKind.page
    else if (std.ascii.eqlIgnoreCase(keyword, "counter-style"))
        CssBlockAtRuleKind.counter_style
    else
        return error.ScriptRuntime;

    const block_start = try parseCssRuleBlockStart(source, pos.*);
    const header_text = std.mem.trim(u8, source[pos.*..block_start], " \t\r\n\x0c");
    if (rule_kind != .font_face and rule_kind != .font_feature_values and rule_kind != .page and rule_kind != .counter_style and rule_kind != .starting_style and rule_kind != .position_try and header_text.len == 0) return error.ScriptRuntime;
    if (rule_kind == .supports_condition and !isDashedIdent(header_text)) return error.ScriptRuntime;
    if (rule_kind == .font_palette_values and !std.mem.startsWith(u8, header_text, "--")) return error.ScriptRuntime;

    const block_end = try parseCssRuleBlockEnd(source, block_start + 1);
    const css_text = std.mem.trim(u8, source[at_start..block_end], " \t\r\n\x0c");
    pos.* = block_end;

    return switch (rule_kind) {
        .media => Value{ .css_rule = .{
            .media = .{
                .condition_text = header_text,
                .css_text = css_text,
                .css_rules = try parseStyleSheetRuleValues(allocator, source[block_start + 1 .. block_end - 1]),
            },
        } },
        .supports => Value{ .css_rule = .{
            .supports = .{
                .condition_text = header_text,
                .css_text = css_text,
                .css_rules = try parseStyleSheetRuleValues(allocator, source[block_start + 1 .. block_end - 1]),
            },
        } },
        .supports_condition => Value{ .css_rule = .{
            .supports_condition = .{
                .name = header_text,
                .css_text = css_text,
                .css_rules = try allocator.alloc(Value, 0),
            },
        } },
        .document => Value{ .css_rule = .{
            .document = .{
                .condition_text = header_text,
                .css_text = css_text,
                .css_rules = try parseStyleSheetRuleValues(allocator, source[block_start + 1 .. block_end - 1]),
            },
        } },
        .container => Value{ .css_rule = .{
            .container = .{
                .condition_text = header_text,
                .css_text = css_text,
                .css_rules = try parseStyleSheetRuleValues(allocator, source[block_start + 1 .. block_end - 1]),
            },
        } },
        .starting_style => Value{ .css_rule = .{
            .starting_style = .{
                .css_text = css_text,
                .css_rules = try parseStyleSheetRuleValues(allocator, source[block_start + 1 .. block_end - 1]),
            },
        } },
        .position_try => Value{ .css_rule = .{
            .position_try = .{
                .name = header_text,
                .css_text = css_text,
            },
        } },
        .keyframes => Value{ .css_rule = .{
            .keyframes = .{
                .name = header_text,
                .css_text = css_text,
                .css_rules = try parseKeyframesRuleValues(allocator, source[block_start + 1 .. block_end - 1]),
            },
        } },
        .font_face => Value{ .css_rule = .{
            .font_face = .{
                .css_text = css_text,
            },
        } },
        .font_feature_values => Value{ .css_rule = .{
            .font_feature_values = .{
                .font_family = header_text,
                .css_text = css_text,
            },
        } },
        .font_palette_values => blk: {
            const body = std.mem.trim(u8, source[block_start + 1 .. block_end - 1], " \t\r\n\x0c");
            const parsed = try parseCssFontPaletteValuesPrelude(allocator, body);
            break :blk Value{ .css_rule = .{
                .font_palette_values = .{
                    .name = header_text,
                    .font_family = parsed.font_family,
                    .base_palette = parsed.base_palette,
                    .override_colors = parsed.override_colors,
                    .css_text = css_text,
                },
            } };
        },
        .page => Value{ .css_rule = .{
            .page = .{
                .selector_text = header_text,
                .css_text = css_text,
            },
        } },
        .counter_style => blk: {
            const body = std.mem.trim(u8, source[block_start + 1 .. block_end - 1], " \t\r\n\x0c");
            const parsed = try parseCssCounterStylePrelude(allocator, body);
            break :blk Value{ .css_rule = .{
                .counter_style = .{
                    .name = header_text,
                    .system = parsed.system,
                    .symbols = parsed.symbols,
                    .negative = parsed.negative,
                    .prefix = parsed.prefix,
                    .suffix = parsed.suffix,
                    .range = parsed.range,
                    .pad = parsed.pad,
                    .fallback = parsed.fallback,
                    .speak_as = parsed.speak_as,
                    .additive_symbols = parsed.additive_symbols,
                    .css_text = css_text,
                },
            } };
        },
    };
}

const CssBlockAtRuleKind = enum {
    media,
    supports,
    supports_condition,
    document,
    container,
    starting_style,
    position_try,
    keyframes,
    font_face,
    font_feature_values,
    font_palette_values,
    page,
    counter_style,
};

fn parseStyleSheetImportRuleValue(
    allocator: std.mem.Allocator,
    source: []const u8,
    at_start: usize,
    pos: *usize,
) errors.Result(Value) {
    _ = allocator;
    const statement_end = try parseCssRuleStatementEnd(source, pos.*);
    const prelude = std.mem.trim(u8, source[pos.*..statement_end], " \t\r\n\x0c");
    if (prelude.len == 0) return error.ScriptRuntime;

    const parsed = try parseCssImportPrelude(prelude);
    const css_text = std.mem.trim(u8, source[at_start .. statement_end + 1], " \t\r\n\x0c");
    pos.* = statement_end + 1;

    return Value{ .css_rule = .{
        .import = .{
            .href = parsed.href,
            .media_text = parsed.media_text,
            .supports_text = parsed.supports_text,
            .layer_name = parsed.layer_name,
            .css_text = css_text,
        },
    } };
}

fn parseStyleSheetCharsetRuleValue(
    allocator: std.mem.Allocator,
    source: []const u8,
    at_start: usize,
    pos: *usize,
) errors.Result(Value) {
    _ = allocator;
    const statement_end = try parseCssRuleStatementEnd(source, pos.*);
    const prelude = std.mem.trim(u8, source[pos.*..statement_end], " \t\r\n\x0c");
    if (prelude.len == 0) return error.ScriptRuntime;

    const parsed = try parseCssCharsetPrelude(prelude);
    const css_text = std.mem.trim(u8, source[at_start .. statement_end + 1], " \t\r\n\x0c");
    pos.* = statement_end + 1;

    return Value{ .css_rule = .{
        .charset = .{
            .encoding = parsed.encoding,
            .css_text = css_text,
        },
    } };
}

const CssImportPrelude = struct {
    href: []const u8,
    media_text: []const u8,
    supports_text: []const u8,
    layer_name: []const u8,
};

const CssCharsetPrelude = struct {
    encoding: []const u8,
};

fn parseCssCharsetPrelude(prelude: []const u8) errors.Result(CssCharsetPrelude) {
    var pos: usize = 0;
    pos = try skipCssTrivia(prelude, pos);
    if (pos >= prelude.len) return error.ScriptRuntime;
    if (prelude[pos] != '"' and prelude[pos] != '\'') return error.ScriptRuntime;

    const quote = prelude[pos];
    pos += 1;
    const start = pos;
    while (pos < prelude.len) : (pos += 1) {
        const byte = prelude[pos];
        if (byte == '\\') {
            if (pos + 1 >= prelude.len) return error.ScriptRuntime;
            pos += 1;
            continue;
        }
        if (byte == quote) {
            const encoding = prelude[start..pos];
            pos += 1;
            pos = try skipCssTrivia(prelude, pos);
            if (pos != prelude.len) return error.ScriptRuntime;
            return .{ .encoding = encoding };
        }
    }

    return error.ScriptRuntime;
}

const CssNamespacePrelude = struct {
    prefix: []const u8,
    namespace_uri: []const u8,
};

const CssPropertyPrelude = struct {
    syntax: []const u8,
    inherits: bool,
    initial_value: []const u8,
};

const CssCounterStylePrelude = struct {
    system: []const u8,
    symbols: []const u8,
    negative: []const u8,
    prefix: []const u8,
    suffix: []const u8,
    range: []const u8,
    pad: []const u8,
    fallback: []const u8,
    speak_as: []const u8,
    additive_symbols: []const u8,
};

const CssFontPaletteValuesPrelude = struct {
    font_family: []const u8 = "",
    base_palette: []const u8 = "",
    override_colors: []const u8 = "",
};

const CssScopePrelude = struct {
    start_text: ?[]const u8,
    end_text: ?[]const u8,
};

fn parseStyleSheetPropertyRuleValue(
    allocator: std.mem.Allocator,
    source: []const u8,
    at_start: usize,
    pos: *usize,
) errors.Result(Value) {
    const block_start = try parseCssRuleBlockStart(source, pos.*);
    const name_text = std.mem.trim(u8, source[pos.*..block_start], " \t\r\n\x0c");
    if (!std.mem.startsWith(u8, name_text, "--")) return error.ScriptRuntime;
    if (name_text.len == 2) return error.ScriptRuntime;

    const block_end = try parseCssRuleBlockEnd(source, block_start + 1);
    const css_text = std.mem.trim(u8, source[at_start..block_end], " \t\r\n\x0c");
    pos.* = block_end;

    const body = std.mem.trim(u8, source[block_start + 1 .. block_end - 1], " \t\r\n\x0c");
    const parsed = try parseCssPropertyPrelude(allocator, body);
    return Value{ .css_rule = .{
        .property = .{
            .name = name_text,
            .syntax = parsed.syntax,
            .inherits = parsed.inherits,
            .initial_value = parsed.initial_value,
            .css_text = css_text,
        },
    } };
}

fn parseCssPropertyPrelude(allocator: std.mem.Allocator, prelude: []const u8) errors.Result(CssPropertyPrelude) {
    var entries = try parseStyleDeclarations(allocator, prelude);
    defer freeStyleDeclarations(allocator, &entries);

    var syntax: ?[]const u8 = null;
    errdefer if (syntax) |value| allocator.free(value);
    var inherits: ?bool = null;
    var initial_value: []const u8 = "";
    errdefer if (initial_value.len != 0) allocator.free(initial_value);

    for (entries.items) |entry| {
        if (std.mem.eql(u8, entry.name, "syntax")) {
            syntax = try allocator.dupe(u8, entry.value);
            continue;
        }
        if (std.mem.eql(u8, entry.name, "inherits")) {
            if (std.ascii.eqlIgnoreCase(entry.value, "true")) {
                inherits = true;
            } else if (std.ascii.eqlIgnoreCase(entry.value, "false")) {
                inherits = false;
            } else {
                return error.ScriptRuntime;
            }
            continue;
        }
        if (std.mem.eql(u8, entry.name, "initial-value")) {
            initial_value = try allocator.dupe(u8, entry.value);
            continue;
        }
    }

    const syntax_value = syntax orelse return error.ScriptRuntime;
    const inherits_value = inherits orelse return error.ScriptRuntime;
    return .{
        .syntax = syntax_value,
        .inherits = inherits_value,
        .initial_value = initial_value,
    };
}

fn parseCssCounterStylePrelude(
    allocator: std.mem.Allocator,
    prelude: []const u8,
) errors.Result(CssCounterStylePrelude) {
    var entries = try parseStyleDeclarations(allocator, prelude);
    defer freeStyleDeclarations(allocator, &entries);

    var system: []const u8 = "";
    errdefer if (system.len != 0) allocator.free(system);
    var symbols: []const u8 = "";
    errdefer if (symbols.len != 0) allocator.free(symbols);
    var negative: []const u8 = "";
    errdefer if (negative.len != 0) allocator.free(negative);
    var prefix: []const u8 = "";
    errdefer if (prefix.len != 0) allocator.free(prefix);
    var suffix: []const u8 = "";
    errdefer if (suffix.len != 0) allocator.free(suffix);
    var range: []const u8 = "";
    errdefer if (range.len != 0) allocator.free(range);
    var pad: []const u8 = "";
    errdefer if (pad.len != 0) allocator.free(pad);
    var fallback: []const u8 = "";
    errdefer if (fallback.len != 0) allocator.free(fallback);
    var speak_as: []const u8 = "";
    errdefer if (speak_as.len != 0) allocator.free(speak_as);
    var additive_symbols: []const u8 = "";
    errdefer if (additive_symbols.len != 0) allocator.free(additive_symbols);

    system = try colorProfileDescriptorText(allocator, entries.items, "system");
    symbols = try colorProfileDescriptorText(allocator, entries.items, "symbols");
    negative = try colorProfileDescriptorText(allocator, entries.items, "negative");
    prefix = try colorProfileDescriptorText(allocator, entries.items, "prefix");
    suffix = try colorProfileDescriptorText(allocator, entries.items, "suffix");
    range = try colorProfileDescriptorText(allocator, entries.items, "range");
    pad = try colorProfileDescriptorText(allocator, entries.items, "pad");
    fallback = try colorProfileDescriptorText(allocator, entries.items, "fallback");
    speak_as = try colorProfileDescriptorText(allocator, entries.items, "speak-as");
    additive_symbols = try colorProfileDescriptorText(allocator, entries.items, "additive-symbols");

    return .{
        .system = system,
        .symbols = symbols,
        .negative = negative,
        .prefix = prefix,
        .suffix = suffix,
        .range = range,
        .pad = pad,
        .fallback = fallback,
        .speak_as = speak_as,
        .additive_symbols = additive_symbols,
    };
}

fn parseCssFontPaletteValuesPrelude(
    allocator: std.mem.Allocator,
    prelude: []const u8,
) errors.Result(CssFontPaletteValuesPrelude) {
    var entries = try parseStyleDeclarations(allocator, prelude);
    defer freeStyleDeclarations(allocator, &entries);

    var font_family: []const u8 = "";
    errdefer if (font_family.len != 0) allocator.free(font_family);
    var base_palette: []const u8 = "";
    errdefer if (base_palette.len != 0) allocator.free(base_palette);
    var override_colors: []const u8 = "";
    errdefer if (override_colors.len != 0) allocator.free(override_colors);

    for (entries.items) |entry| {
        if (std.mem.eql(u8, entry.name, "font-family")) {
            if (font_family.len != 0) allocator.free(font_family);
            font_family = try allocator.dupe(u8, entry.value);
            continue;
        }
        if (std.mem.eql(u8, entry.name, "base-palette")) {
            if (base_palette.len != 0) allocator.free(base_palette);
            base_palette = try allocator.dupe(u8, entry.value);
            continue;
        }
        if (std.mem.eql(u8, entry.name, "override-colors")) {
            if (override_colors.len != 0) allocator.free(override_colors);
            override_colors = try allocator.dupe(u8, entry.value);
            continue;
        }
    }

    return .{
        .font_family = font_family,
        .base_palette = base_palette,
        .override_colors = override_colors,
    };
}

fn parseStyleSheetLayerRuleValue(
    allocator: std.mem.Allocator,
    source: []const u8,
    at_start: usize,
    pos: *usize,
) errors.Result(Value) {
    const prelude = try parseCssLayerPreludeKind(source, pos.*);
    return switch (prelude.kind) {
        .block => blk: {
            const block_start = prelude.delimiter;
            const name_text = std.mem.trim(u8, source[pos.*..block_start], " \t\r\n\x0c");
            const block_end = try parseCssRuleBlockEnd(source, block_start + 1);
            const css_text = std.mem.trim(u8, source[at_start..block_end], " \t\r\n\x0c");
            pos.* = block_end;

            break :blk Value{ .css_rule = .{
                .layer = .{
                    .name_text = name_text,
                    .css_text = css_text,
                    .css_rules = try parseStyleSheetRuleValues(allocator, source[block_start + 1 .. block_end - 1]),
                },
            } };
        },
        .statement => blk: {
            const statement_end = prelude.delimiter;
            const name_text = std.mem.trim(u8, source[pos.*..statement_end], " \t\r\n\x0c");
            if (name_text.len == 0) return error.ScriptRuntime;
            const css_text = std.mem.trim(u8, source[at_start .. statement_end + 1], " \t\r\n\x0c");
            pos.* = statement_end + 1;

            break :blk Value{ .css_rule = .{
                .layer = .{
                    .name_text = name_text,
                    .css_text = css_text,
                    .css_rules = try allocator.alloc(Value, 0),
                    .is_statement = true,
                },
            } };
        },
    };
}

const CssLayerPreludeKind = struct {
    kind: enum { block, statement },
    delimiter: usize,
};

fn parseCssLayerPreludeKind(source: []const u8, start: usize) errors.Result(CssLayerPreludeKind) {
    var pos = start;
    var paren_depth: usize = 0;
    var in_string: ?u8 = null;
    while (pos < source.len) {
        const byte = source[pos];
        if (in_string) |quote| {
            if (byte == '\\') {
                if (pos + 1 >= source.len) return error.ScriptRuntime;
                pos += 2;
                continue;
            }
            if (byte == quote) in_string = null;
            pos += 1;
            continue;
        }
        if (byte == '"' or byte == '\'') {
            in_string = byte;
            pos += 1;
            continue;
        }
        if (byte == '/' and pos + 1 < source.len and source[pos + 1] == '*') {
            pos = try skipCssComment(source, pos);
            continue;
        }
        if (byte == '(') {
            paren_depth += 1;
            pos += 1;
            continue;
        }
        if (byte == ')') {
            if (paren_depth == 0) return error.ScriptRuntime;
            paren_depth -= 1;
            pos += 1;
            continue;
        }
        if (paren_depth == 0) {
            if (byte == '{') return .{ .kind = .block, .delimiter = pos };
            if (byte == ';') return .{ .kind = .statement, .delimiter = pos };
            if (byte == '}') return error.ScriptRuntime;
        }
        pos += 1;
    }
    return error.ScriptRuntime;
}

fn parseStyleSheetScopeRuleValue(
    allocator: std.mem.Allocator,
    source: []const u8,
    at_start: usize,
    pos: *usize,
) errors.Result(Value) {
    const block_start = try parseCssRuleBlockStart(source, pos.*);
    const prelude = std.mem.trim(u8, source[pos.*..block_start], " \t\r\n\x0c");
    if (prelude.len == 0) return error.ScriptRuntime;

    const parsed = try parseCssScopePrelude(prelude);
    const block_end = try parseCssRuleBlockEnd(source, block_start + 1);
    const css_text = std.mem.trim(u8, source[at_start..block_end], " \t\r\n\x0c");
    pos.* = block_end;

    return Value{ .css_rule = .{
        .scope = .{
            .start_text = parsed.start_text,
            .end_text = parsed.end_text,
            .css_text = css_text,
            .css_rules = try parseStyleSheetRuleValues(allocator, source[block_start + 1 .. block_end - 1]),
        },
    } };
}

fn parseCssScopePrelude(prelude: []const u8) errors.Result(CssScopePrelude) {
    var pos: usize = 0;
    pos = try skipCssTrivia(prelude, pos);
    if (pos >= prelude.len) return error.ScriptRuntime;

    if (isCssScopeToKeyword(prelude, pos)) {
        pos += 2;
        pos = try skipCssTrivia(prelude, pos);
        const end_text = try parseCssScopePreludeGroup(prelude, &pos);
        pos = try skipCssTrivia(prelude, pos);
        if (pos != prelude.len) return error.ScriptRuntime;
        return .{
            .start_text = null,
            .end_text = end_text,
        };
    }

    const start_text = try parseCssScopePreludeGroup(prelude, &pos);
    pos = try skipCssTrivia(prelude, pos);
    if (pos >= prelude.len) {
        return .{
            .start_text = start_text,
            .end_text = null,
        };
    }
    if (!isCssScopeToKeyword(prelude, pos)) return error.ScriptRuntime;
    pos += 2;
    pos = try skipCssTrivia(prelude, pos);
    const end_text = try parseCssScopePreludeGroup(prelude, &pos);
    pos = try skipCssTrivia(prelude, pos);
    if (pos != prelude.len) return error.ScriptRuntime;
    return .{
        .start_text = start_text,
        .end_text = end_text,
    };
}

fn parseCssScopePreludeGroup(prelude: []const u8, pos: *usize) errors.Result([]const u8) {
    if (pos.* >= prelude.len or prelude[pos.*] != '(') return error.ScriptRuntime;

    const text_start = pos.* + 1;
    var scan = text_start;
    var depth: usize = 1;
    var in_string: ?u8 = null;
    while (scan < prelude.len) {
        const byte = prelude[scan];
        if (in_string) |quote| {
            if (byte == '\\') {
                if (scan + 1 >= prelude.len) return error.ScriptRuntime;
                scan += 2;
                continue;
            }
            if (byte == quote) in_string = null;
            scan += 1;
            continue;
        }
        if (byte == '"' or byte == '\'') {
            in_string = byte;
            scan += 1;
            continue;
        }
        if (byte == '/' and scan + 1 < prelude.len and prelude[scan + 1] == '*') {
            scan = try skipCssComment(prelude, scan);
            continue;
        }
        if (byte == '(') {
            depth += 1;
            scan += 1;
            continue;
        }
        if (byte == ')') {
            depth -= 1;
            scan += 1;
            if (depth == 0) {
                const text = std.mem.trim(u8, prelude[text_start .. scan - 1], " \t\r\n\x0c");
                if (text.len == 0) return error.ScriptRuntime;
                pos.* = scan;
                return text;
            }
            continue;
        }
        scan += 1;
    }

    return error.ScriptRuntime;
}

fn isCssScopeToKeyword(prelude: []const u8, pos: usize) bool {
    if (pos + 2 > prelude.len) return false;
    if (!std.ascii.eqlIgnoreCase(prelude[pos .. pos + 2], "to")) return false;
    return pos + 2 == prelude.len or !isIdentifierContinueByte(prelude[pos + 2]);
}

fn parseCssImportPrelude(prelude: []const u8) errors.Result(CssImportPrelude) {
    var pos: usize = 0;
    pos = try skipCssTrivia(prelude, pos);
    if (pos >= prelude.len) return error.ScriptRuntime;

    const href: []const u8 = href_blk: {
        if (prelude[pos] == '"' or prelude[pos] == '\'') {
            const quote = prelude[pos];
            pos += 1;
            const start = pos;
            while (pos < prelude.len) : (pos += 1) {
                const byte = prelude[pos];
                if (byte == '\\') {
                    if (pos + 1 >= prelude.len) return error.ScriptRuntime;
                    pos += 2;
                    continue;
                }
                if (byte == quote) {
                    break;
                }
            }
            if (pos >= prelude.len or prelude[pos] != quote) return error.ScriptRuntime;
            const value = prelude[start..pos];
            pos += 1;
            break :href_blk value;
        }

        if (pos + 4 <= prelude.len and std.ascii.eqlIgnoreCase(prelude[pos .. pos + 4], "url(")) {
            pos += 4;
            pos = try skipCssTrivia(prelude, pos);
            if (pos >= prelude.len) return error.ScriptRuntime;

            if (prelude[pos] == '"' or prelude[pos] == '\'') {
                const quote = prelude[pos];
                pos += 1;
                const start = pos;
                while (pos < prelude.len) : (pos += 1) {
                    const byte = prelude[pos];
                    if (byte == '\\') {
                        if (pos + 1 >= prelude.len) return error.ScriptRuntime;
                        pos += 2;
                        continue;
                    }
                    if (byte == quote) {
                        break;
                    }
                }
                if (pos >= prelude.len or prelude[pos] != quote) return error.ScriptRuntime;
                const value = prelude[start..pos];
                pos += 1;
                pos = try skipCssTrivia(prelude, pos);
                if (pos >= prelude.len or prelude[pos] != ')') return error.ScriptRuntime;
                pos += 1;
                break :href_blk value;
            }

            const start = pos;
            while (pos < prelude.len and prelude[pos] != ')') : (pos += 1) {
                if (prelude[pos] == '\\') {
                    if (pos + 1 >= prelude.len) return error.ScriptRuntime;
                    pos += 2;
                    continue;
                }
            }
            if (pos >= prelude.len or prelude[pos] != ')') return error.ScriptRuntime;
            const value = std.mem.trim(u8, prelude[start..pos], " \t\r\n\x0c");
            if (value.len == 0) return error.ScriptRuntime;
            pos += 1;
            break :href_blk value;
        }

        return error.ScriptRuntime;
    };

    var supports_text: []const u8 = "";
    var layer_name: []const u8 = "";
    var has_supports = false;
    var has_layer = false;

    while (true) {
        pos = try skipCssTrivia(prelude, pos);
        if (pos >= prelude.len) break;

        if (!has_supports and isCssImportKeyword(prelude, pos, "supports")) {
            pos += "supports".len;
            pos = try skipCssTrivia(prelude, pos);
            if (pos >= prelude.len) return error.ScriptRuntime;
            supports_text = try parseCssScopePreludeGroup(prelude, &pos);
            has_supports = true;
            continue;
        }

        if (!has_layer and isCssImportKeyword(prelude, pos, "layer")) {
            pos += "layer".len;
            pos = try skipCssTrivia(prelude, pos);
            if (pos < prelude.len and prelude[pos] == '(') {
                layer_name = try parseCssScopePreludeGroup(prelude, &pos);
            } else {
                layer_name = "";
            }
            has_layer = true;
            continue;
        }

        break;
    }

    pos = try skipCssTrivia(prelude, pos);
    const media_text = std.mem.trim(u8, prelude[pos..], " \t\r\n\x0c");
    return .{
        .href = href,
        .media_text = media_text,
        .supports_text = supports_text,
        .layer_name = layer_name,
    };
}

fn isCssImportKeyword(prelude: []const u8, pos: usize, keyword: []const u8) bool {
    if (pos + keyword.len > prelude.len) return false;
    if (!std.ascii.eqlIgnoreCase(prelude[pos .. pos + keyword.len], keyword)) return false;
    return pos + keyword.len == prelude.len or !isIdentifierContinueByte(prelude[pos + keyword.len]);
}

fn parseCssContainerConditionParts(text: []const u8) CssContainerConditionParts {
    const trimmed = std.mem.trim(u8, text, " \t\r\n\x0c");
    if (trimmed.len == 0) return .{ .name = "", .query = "" };

    if (cssContainerQueryStarts(trimmed)) {
        return .{ .name = "", .query = trimmed };
    }

    const name_end = cssContainerNameEnd(trimmed) orelse return .{ .name = "", .query = trimmed };
    const name = trimmed[0..name_end];
    if (isCssContainerReservedName(name)) return .{ .name = "", .query = trimmed };

    const query = std.mem.trim(u8, trimmed[name_end..], " \t\r\n\x0c");
    if (query.len == 0) return .{ .name = name, .query = "" };
    if (cssContainerQueryStarts(query)) return .{ .name = name, .query = query };

    return .{ .name = "", .query = trimmed };
}

fn cssContainerNameEnd(text: []const u8) ?usize {
    if (text.len == 0) return null;

    var pos: usize = 0;
    if (std.ascii.isAlphabetic(text[pos]) or text[pos] == '_') {
        pos += 1;
    } else if (text[pos] == '-') {
        if (text.len < 2) return null;
        const second = text[1];
        if (!(std.ascii.isAlphabetic(second) or second == '_' or second == '-')) return null;
        pos += 2;
    } else {
        return null;
    }

    while (pos < text.len and (isIdentifierContinueByte(text[pos]) or text[pos] == '-')) {
        pos += 1;
    }

    return pos;
}

fn cssContainerQueryStarts(text: []const u8) bool {
    if (text.len == 0) return false;
    if (text[0] == '(') return true;
    if (text.len >= 6 and std.ascii.eqlIgnoreCase(text[0..6], "style(")) return true;
    if (text.len >= 13 and std.ascii.eqlIgnoreCase(text[0..13], "scroll-state(")) return true;
    return text.len >= 3 and std.ascii.eqlIgnoreCase(text[0..3], "not") and (text.len == 3 or isWhitespaceByte(text[3]) or text[3] == '(');
}

fn isCssContainerReservedName(name: []const u8) bool {
    return std.ascii.eqlIgnoreCase(name, "none") or
        std.ascii.eqlIgnoreCase(name, "and") or
        std.ascii.eqlIgnoreCase(name, "not") or
        std.ascii.eqlIgnoreCase(name, "or");
}

fn parseStyleSheetNamespaceRuleValue(
    allocator: std.mem.Allocator,
    source: []const u8,
    at_start: usize,
    pos: *usize,
) errors.Result(Value) {
    _ = allocator;
    const statement_end = try parseCssRuleStatementEnd(source, pos.*);
    const prelude = std.mem.trim(u8, source[pos.*..statement_end], " \t\r\n\x0c");
    if (prelude.len == 0) return error.ScriptRuntime;

    const parsed = try parseCssNamespacePrelude(prelude);
    const css_text = std.mem.trim(u8, source[at_start .. statement_end + 1], " \t\r\n\x0c");
    pos.* = statement_end + 1;

    return Value{ .css_rule = .{
        .namespace = .{
            .prefix = parsed.prefix,
            .namespace_uri = parsed.namespace_uri,
            .css_text = css_text,
        },
    } };
}

fn parseStyleSheetFontPaletteValuesRuleValue(
    allocator: std.mem.Allocator,
    source: []const u8,
    at_start: usize,
    pos: *usize,
) errors.Result(Value) {
    _ = allocator;
    const block_start = try parseCssRuleBlockStart(source, pos.*);
    const name = std.mem.trim(u8, source[pos.*..block_start], " \t\r\n\x0c");
    if (name.len == 0 or !std.mem.startsWith(u8, name, "--")) return error.ScriptRuntime;

    const block_end = try parseCssRuleBlockEnd(source, block_start + 1);
    const css_text = std.mem.trim(u8, source[at_start..block_end], " \t\r\n\x0c");
    pos.* = block_end;

    return Value{ .css_rule = .{
        .font_palette_values = .{
            .name = name,
            .css_text = css_text,
        },
    } };
}

fn parseStyleSheetColorProfileRuleValue(
    allocator: std.mem.Allocator,
    source: []const u8,
    at_start: usize,
    pos: *usize,
) errors.Result(Value) {
    const block_start = try parseCssRuleBlockStart(source, pos.*);
    const name = std.mem.trim(u8, source[pos.*..block_start], " \t\r\n\x0c");
    if (name.len == 0) return error.ScriptRuntime;
    if (!isDashedIdent(name) and !std.ascii.eqlIgnoreCase(name, "device-cmyk")) return error.ScriptRuntime;

    const block_end = try parseCssRuleBlockEnd(source, block_start + 1);
    const css_text = std.mem.trim(u8, source[at_start..block_end], " \t\r\n\x0c");
    pos.* = block_end;

    const descriptors = std.mem.trim(u8, source[block_start + 1 .. block_end - 1], " \t\r\n\x0c");
    var entries = try parseStyleDeclarations(allocator, descriptors);
    defer freeStyleDeclarations(allocator, &entries);

    const src = try colorProfileDescriptorText(allocator, entries.items, "src");
    const rendering_intent = try colorProfileDescriptorText(allocator, entries.items, "rendering-intent");
    const components = try colorProfileDescriptorText(allocator, entries.items, "components");

    return Value{ .css_rule = .{
        .color_profile = .{
            .name = name,
            .src = src,
            .rendering_intent = rendering_intent,
            .components = components,
            .css_text = css_text,
        },
    } };
}

fn colorProfileDescriptorText(
    allocator: std.mem.Allocator,
    entries: []const StylePropertyEntry,
    name: []const u8,
) errors.Result([]const u8) {
    for (entries) |entry| {
        if (std.mem.eql(u8, entry.name, name)) {
            return allocator.dupe(u8, entry.value);
        }
    }
    return allocator.dupe(u8, "");
}

fn isDashedIdent(text: []const u8) bool {
    if (!std.mem.startsWith(u8, text, "--")) return false;
    if (text.len == 2) return false;
    for (text[2..]) |byte| {
        if (!isIdentifierContinueByte(byte) and byte != '-') return false;
    }
    return true;
}

fn parseCssNamespacePrelude(prelude: []const u8) errors.Result(CssNamespacePrelude) {
    var pos: usize = 0;
    pos = try skipCssTrivia(prelude, pos);
    if (pos >= prelude.len) return error.ScriptRuntime;

    var prefix: []const u8 = "";
    const prefix_start = pos;
    if (isIdentifierStartByte(prelude[pos])) {
        pos += 1;
        while (pos < prelude.len and isIdentifierContinueByte(prelude[pos])) {
            pos += 1;
        }
        const after_prefix = try skipCssTrivia(prelude, pos);
        if (after_prefix > pos) {
            prefix = prelude[prefix_start..pos];
            pos = after_prefix;
        } else {
            pos = prefix_start;
        }
    }

    pos = try skipCssTrivia(prelude, pos);
    if (pos >= prelude.len) return error.ScriptRuntime;

    const namespace_uri: []const u8 = href_blk: {
        if (prelude[pos] == '"' or prelude[pos] == '\'') {
            const quote = prelude[pos];
            pos += 1;
            const start = pos;
            while (pos < prelude.len) : (pos += 1) {
                const byte = prelude[pos];
                if (byte == '\\') {
                    if (pos + 1 >= prelude.len) return error.ScriptRuntime;
                    pos += 2;
                    continue;
                }
                if (byte == quote) {
                    break;
                }
            }
            if (pos >= prelude.len or prelude[pos] != quote) return error.ScriptRuntime;
            const value = prelude[start..pos];
            pos += 1;
            break :href_blk value;
        }

        if (pos + 4 <= prelude.len and std.ascii.eqlIgnoreCase(prelude[pos .. pos + 4], "url(")) {
            pos += 4;
            pos = try skipCssTrivia(prelude, pos);
            if (pos >= prelude.len) return error.ScriptRuntime;

            if (prelude[pos] == '"' or prelude[pos] == '\'') {
                const quote = prelude[pos];
                pos += 1;
                const start = pos;
                while (pos < prelude.len) : (pos += 1) {
                    const byte = prelude[pos];
                    if (byte == '\\') {
                        if (pos + 1 >= prelude.len) return error.ScriptRuntime;
                        pos += 2;
                        continue;
                    }
                    if (byte == quote) {
                        break;
                    }
                }
                if (pos >= prelude.len or prelude[pos] != quote) return error.ScriptRuntime;
                const value = prelude[start..pos];
                pos += 1;
                pos = try skipCssTrivia(prelude, pos);
                if (pos >= prelude.len or prelude[pos] != ')') return error.ScriptRuntime;
                pos += 1;
                break :href_blk value;
            }

            const start = pos;
            while (pos < prelude.len and prelude[pos] != ')') : (pos += 1) {
                if (prelude[pos] == '\\') {
                    if (pos + 1 >= prelude.len) return error.ScriptRuntime;
                    pos += 2;
                    continue;
                }
            }
            if (pos >= prelude.len or prelude[pos] != ')') return error.ScriptRuntime;
            const value = std.mem.trim(u8, prelude[start..pos], " \t\r\n\x0c");
            if (value.len == 0) return error.ScriptRuntime;
            pos += 1;
            break :href_blk value;
        }

        return error.ScriptRuntime;
    };

    pos = try skipCssTrivia(prelude, pos);
    if (pos != prelude.len) return error.ScriptRuntime;

    return .{
        .prefix = prefix,
        .namespace_uri = namespace_uri,
    };
}

fn parseCssRuleStatementEnd(
    source: []const u8,
    start: usize,
) errors.Result(usize) {
    var pos = start;
    var paren_depth: usize = 0;
    var in_string: ?u8 = null;
    while (pos < source.len) {
        const byte = source[pos];
        if (in_string) |quote| {
            if (byte == '\\') {
                if (pos + 1 >= source.len) return error.ScriptRuntime;
                pos += 2;
                continue;
            }
            if (byte == quote) in_string = null;
            pos += 1;
            continue;
        }
        if (byte == '"' or byte == '\'') {
            in_string = byte;
            pos += 1;
            continue;
        }
        if (byte == '/' and pos + 1 < source.len and source[pos + 1] == '*') {
            pos = try skipCssComment(source, pos);
            continue;
        }
        if (byte == '(') {
            paren_depth += 1;
            pos += 1;
            continue;
        }
        if (byte == ')') {
            if (paren_depth == 0) return error.ScriptRuntime;
            paren_depth -= 1;
            pos += 1;
            continue;
        }
        if (byte == ';' and paren_depth == 0) return pos;
        if (byte == '{' or byte == '}') return error.ScriptRuntime;
        pos += 1;
    }
    return error.ScriptRuntime;
}

fn parseKeyframesRuleValues(
    allocator: std.mem.Allocator,
    source: []const u8,
) errors.Result([]Value) {
    var rules: std.ArrayList(Value) = .empty;
    errdefer rules.deinit(allocator);

    var pos: usize = 0;
    while (true) {
        pos = try skipCssTrivia(source, pos);
        if (pos >= source.len) break;
        try rules.append(allocator, try parseKeyframesRuleValue(allocator, source, &pos));
    }

    return try allocator.dupe(Value, rules.items);
}

fn parseKeyframesRuleValue(
    allocator: std.mem.Allocator,
    source: []const u8,
    pos: *usize,
) errors.Result(Value) {
    _ = allocator;
    if (source[pos.*] == '@') return error.ScriptRuntime;

    const key_start = pos.*;
    const block_start = try parseCssRuleBlockStart(source, pos.*);
    const key_text = std.mem.trim(u8, source[key_start..block_start], " \t\r\n\x0c");
    if (key_text.len == 0) return error.ScriptRuntime;

    const block_end = try parseCssRuleBlockEnd(source, block_start + 1);
    const css_text = std.mem.trim(u8, source[key_start..block_end], " \t\r\n\x0c");
    pos.* = block_end;

    return Value{ .css_rule = .{
        .keyframe = .{
            .key_text = key_text,
            .css_text = css_text,
        },
    } };
}

fn parseCssRuleBlockStart(
    source: []const u8,
    start: usize,
) errors.Result(usize) {
    var pos = start;
    var in_string: ?u8 = null;
    while (pos < source.len) {
        const byte = source[pos];
        if (in_string) |quote| {
            if (byte == '\\') {
                if (pos + 1 >= source.len) return error.ScriptRuntime;
                pos += 2;
                continue;
            }
            if (byte == quote) in_string = null;
            pos += 1;
            continue;
        }
        if (byte == '"' or byte == '\'') {
            in_string = byte;
            pos += 1;
            continue;
        }
        if (byte == '/' and pos + 1 < source.len and source[pos + 1] == '*') {
            pos = try skipCssComment(source, pos);
            continue;
        }
        if (byte == '{') return pos;
        if (byte == '}') return error.ScriptRuntime;
        pos += 1;
    }
    return error.ScriptRuntime;
}

fn parseCssRuleBlockEnd(
    source: []const u8,
    start: usize,
) errors.Result(usize) {
    var pos = start;
    var depth: usize = 1;
    var in_string: ?u8 = null;
    while (pos < source.len) {
        const byte = source[pos];
        if (in_string) |quote| {
            if (byte == '\\') {
                if (pos + 1 >= source.len) return error.ScriptRuntime;
                pos += 2;
                continue;
            }
            if (byte == quote) in_string = null;
            pos += 1;
            continue;
        }
        if (byte == '"' or byte == '\'') {
            in_string = byte;
            pos += 1;
            continue;
        }
        if (byte == '/' and pos + 1 < source.len and source[pos + 1] == '*') {
            pos = try skipCssComment(source, pos);
            continue;
        }
        if (byte == '{') {
            depth += 1;
            pos += 1;
            continue;
        }
        if (byte == '}') {
            depth -= 1;
            pos += 1;
            if (depth == 0) return pos;
            continue;
        }
        pos += 1;
    }
    return error.ScriptRuntime;
}

fn skipCssTrivia(
    source: []const u8,
    start: usize,
) errors.Result(usize) {
    var pos = start;
    while (pos < source.len) {
        if (isCssWhitespace(source[pos]) or source[pos] == ';') {
            pos += 1;
            continue;
        }
        if (source[pos] == '/' and pos + 1 < source.len and source[pos + 1] == '*') {
            pos = try skipCssComment(source, pos);
            continue;
        }
        break;
    }
    return pos;
}

fn skipCssComment(
    source: []const u8,
    start: usize,
) errors.Result(usize) {
    if (start + 1 >= source.len or source[start] != '/' or source[start + 1] != '*') return error.ScriptRuntime;
    var pos = start + 2;
    while (pos + 1 < source.len) : (pos += 1) {
        if (source[pos] == '*' and source[pos + 1] == '/') {
            return pos + 2;
        }
    }
    return error.ScriptRuntime;
}

fn isCssWhitespace(byte: u8) bool {
    return switch (byte) {
        ' ', '\t', '\n', '\r', 0x0c => true,
        else => false,
    };
}

fn appendAllElementIds(
    allocator: std.mem.Allocator,
    host: anytype,
    node_id: dom.NodeId,
    filtered: *std.ArrayList(dom.NodeId),
) errors.Result(void) {
    const children = host.domStore().childIds(node_id);
    for (children) |child_id| {
        if (host.domStore().tagNameForNode(child_id) != null) {
            try filtered.append(allocator, child_id);
        }
        try appendAllElementIds(allocator, host, child_id, filtered);
    }
}

fn appendStyleSheetIds(
    allocator: std.mem.Allocator,
    host: anytype,
    node_id: dom.NodeId,
    filtered: *std.ArrayList(dom.NodeId),
) errors.Result(void) {
    const children = host.domStore().childIds(node_id);
    for (children) |child_id| {
        const tag_name = host.domStore().tagNameForNode(child_id) orelse {
            try appendStyleSheetIds(allocator, host, child_id, filtered);
            continue;
        };

        if (std.mem.eql(u8, tag_name, "style") or try isStyleSheetLinkElement(host, child_id)) {
            try filtered.append(allocator, child_id);
        }
        try appendStyleSheetIds(allocator, host, child_id, filtered);
    }
}

fn isStyleSheetLinkElement(host: anytype, element_id: dom.NodeId) errors.Result(bool) {
    const tag_name = host.domStore().tagNameForNode(element_id) orelse return false;
    if (!std.mem.eql(u8, tag_name, "link")) return false;

    const rel_value = (try host.domStore().getAttribute(element_id, "rel")) orelse return false;
    var rels = std.mem.tokenizeAny(u8, rel_value, " \t\r\n\x0c");
    while (rels.next()) |rel| {
        if (std.ascii.eqlIgnoreCase(rel, "stylesheet")) return true;
    }
    return false;
}

fn isLabelableElement(host: anytype, element_id: dom.NodeId) errors.Result(bool) {
    const tag_name = host.domStore().tagNameForNode(element_id) orelse return false;
    if (std.ascii.eqlIgnoreCase(tag_name, "input")) {
        const input_type = (try host.domStore().getAttribute(element_id, "type")) orelse "";
        return !std.ascii.eqlIgnoreCase(input_type, "hidden");
    }

    return std.mem.eql(u8, tag_name, "button") or
        std.mem.eql(u8, tag_name, "fieldset") or
        std.mem.eql(u8, tag_name, "meter") or
        std.mem.eql(u8, tag_name, "output") or
        std.mem.eql(u8, tag_name, "progress") or
        std.mem.eql(u8, tag_name, "select") or
        std.mem.eql(u8, tag_name, "textarea");
}

fn elementSupportsLabelProperty(host: anytype, element_id: dom.NodeId) errors.Result(bool) {
    const tag_name = host.domStore().tagNameForNode(element_id) orelse return false;
    return std.mem.eql(u8, tag_name, "label");
}

fn labelControlId(
    allocator: std.mem.Allocator,
    host: anytype,
    label_id: dom.NodeId,
) errors.Result(?dom.NodeId) {
    if (!try elementSupportsLabelProperty(host, label_id)) {
        return error.ScriptRuntime;
    }

    if (try host.domStore().getAttribute(label_id, "for")) |for_value| {
        if (host.domStore().findElementById(for_value)) |control_id| {
            if (try isLabelableElement(host, control_id)) {
                return control_id;
            }
        }
        return null;
    }

    const descendants = try descendantElementIds(allocator, host, label_id);
    defer allocator.free(descendants);

    for (descendants) |candidate_id| {
        if (try isLabelableElement(host, candidate_id)) {
            return candidate_id;
        }
    }

    return null;
}

fn elementSupportsPlaceholderProperty(host: anytype, element_id: dom.NodeId) errors.Result(bool) {
    const tag_name = host.domStore().tagNameForNode(element_id) orelse return false;
    return std.ascii.eqlIgnoreCase(tag_name, "input") or
        std.mem.eql(u8, tag_name, "textarea");
}

fn elementSupportsPatternProperty(host: anytype, element_id: dom.NodeId) errors.Result(bool) {
    const tag_name = host.domStore().tagNameForNode(element_id) orelse return false;
    return std.ascii.eqlIgnoreCase(tag_name, "input");
}

fn elementSupportsTextLengthProperty(host: anytype, element_id: dom.NodeId) errors.Result(bool) {
    const tag_name = host.domStore().tagNameForNode(element_id) orelse return false;
    return std.ascii.eqlIgnoreCase(tag_name, "input") or
        std.mem.eql(u8, tag_name, "textarea");
}

fn elementSupportsInputProperty(host: anytype, element_id: dom.NodeId) errors.Result(bool) {
    const tag_name = host.domStore().tagNameForNode(element_id) orelse return false;
    return std.ascii.eqlIgnoreCase(tag_name, "input");
}

fn elementSupportsFilesProperty(host: anytype, element_id: dom.NodeId) errors.Result(bool) {
    const tag_name = host.domStore().tagNameForNode(element_id) orelse return false;
    if (!std.ascii.eqlIgnoreCase(tag_name, "input")) return false;

    const input_type = (try host.domStore().getAttribute(element_id, "type")) orelse "";
    return std.ascii.eqlIgnoreCase(input_type, "file");
}

fn elementSupportsCaptureProperty(host: anytype, element_id: dom.NodeId) errors.Result(bool) {
    return elementSupportsFilesProperty(host, element_id);
}

fn elementSupportsColorInputProperty(host: anytype, element_id: dom.NodeId) errors.Result(bool) {
    const tag_name = host.domStore().tagNameForNode(element_id) orelse return false;
    if (!std.ascii.eqlIgnoreCase(tag_name, "input")) return false;

    const input_type = (try host.domStore().getAttribute(element_id, "type")) orelse "";
    return std.ascii.eqlIgnoreCase(input_type, "color");
}

fn elementSupportsPickerProperty(host: anytype, element_id: dom.NodeId) errors.Result(bool) {
    const tag_name = host.domStore().tagNameForNode(element_id) orelse return false;
    return std.ascii.eqlIgnoreCase(tag_name, "input") or std.mem.eql(u8, tag_name, "select");
}

fn elementSupportsTrackProperty(host: anytype, element_id: dom.NodeId) errors.Result(bool) {
    const tag_name = host.domStore().tagNameForNode(element_id) orelse return false;
    return std.mem.eql(u8, tag_name, "track");
}

fn elementSupportsPopoverProperty(host: anytype, element_id: dom.NodeId) errors.Result(bool) {
    const namespace_uri = host.domStore().namespaceUriForNode(element_id) orelse return false;
    return std.mem.eql(u8, namespace_uri, "http://www.w3.org/1999/xhtml");
}

fn elementSupportsPopoverTargetProperty(host: anytype, element_id: dom.NodeId) errors.Result(bool) {
    const namespace_uri = host.domStore().namespaceUriForNode(element_id) orelse return false;
    if (!std.mem.eql(u8, namespace_uri, "http://www.w3.org/1999/xhtml")) return false;
    const tag_name = host.domStore().tagNameForNode(element_id) orelse return false;
    return std.mem.eql(u8, tag_name, "button") or std.ascii.eqlIgnoreCase(tag_name, "input");
}

const ButtonTypeState = enum {
    auto,
    submit,
    reset,
    button,
};

const ButtonCommandKind = union(enum) {
    unknown,
    custom: []const u8,
    toggle_popover,
    show_popover,
    hide_popover,
    close,
    request_close,
    show_modal,
};

fn buttonTypeState(host: anytype, element_id: dom.NodeId) errors.Result(ButtonTypeState) {
    const tag_name = host.domStore().tagNameForNode(element_id) orelse return error.ScriptRuntime;
    if (!std.mem.eql(u8, tag_name, "button")) return error.ScriptRuntime;

    const type_text = (try host.domStore().getAttribute(element_id, "type")) orelse return .auto;
    const trimmed = std.mem.trim(u8, type_text, " \t\r\n\x0c");
    if (trimmed.len == 0) return .auto;
    if (std.ascii.eqlIgnoreCase(trimmed, "submit")) return .submit;
    if (std.ascii.eqlIgnoreCase(trimmed, "reset")) return .reset;
    if (std.ascii.eqlIgnoreCase(trimmed, "button")) return .button;
    return .auto;
}

fn buttonCommandKind(host: anytype, element_id: dom.NodeId) errors.Result(ButtonCommandKind) {
    const tag_name = host.domStore().tagNameForNode(element_id) orelse return error.ScriptRuntime;
    if (!std.mem.eql(u8, tag_name, "button")) return error.ScriptRuntime;

    const command_text = (try host.domStore().getAttribute(element_id, "command")) orelse return .unknown;
    const trimmed = std.mem.trim(u8, command_text, " \t\r\n\x0c");
    if (trimmed.len == 0) return .unknown;
    if (trimmed.len >= 2 and trimmed[0] == '-' and trimmed[1] == '-') return .{ .custom = trimmed };
    if (std.ascii.eqlIgnoreCase(trimmed, "toggle-popover")) return .toggle_popover;
    if (std.ascii.eqlIgnoreCase(trimmed, "show-popover")) return .show_popover;
    if (std.ascii.eqlIgnoreCase(trimmed, "hide-popover")) return .hide_popover;
    if (std.ascii.eqlIgnoreCase(trimmed, "close")) return .close;
    if (std.ascii.eqlIgnoreCase(trimmed, "request-close")) return .request_close;
    if (std.ascii.eqlIgnoreCase(trimmed, "show-modal")) return .show_modal;
    return .unknown;
}

pub fn buttonCommandValue(host: anytype, element_id: dom.NodeId) errors.Result([]const u8) {
    return switch (try buttonCommandKind(host, element_id)) {
        .unknown => "",
        .custom => |value| value,
        .toggle_popover => "toggle-popover",
        .show_popover => "show-popover",
        .hide_popover => "hide-popover",
        .close => "close",
        .request_close => "request-close",
        .show_modal => "show-modal",
    };
}

pub fn buttonCommandForElement(host: anytype, element_id: dom.NodeId) errors.Result(?dom.NodeId) {
    const tag_name = host.domStore().tagNameForNode(element_id) orelse return null;
    if (!std.mem.eql(u8, tag_name, "button")) return null;

    const commandfor_text = (try host.domStore().getAttribute(element_id, "commandfor")) orelse return null;
    const trimmed = std.mem.trim(u8, commandfor_text, " \t\r\n\x0c");
    if (trimmed.len == 0) return null;

    return host.domStore().findElementById(trimmed);
}

pub fn buttonCommandValidForTarget(host: anytype, target_id: dom.NodeId, command: []const u8) errors.Result(bool) {
    if (command.len == 0) return false;
    if (command.len >= 2 and command[0] == '-' and command[1] == '-') return true;

    const node = host.domStore().nodeAt(target_id) orelse return false;
    const element = switch (node.kind) {
        .element => |element| element,
        else => return false,
    };
    if (!std.mem.eql(u8, element.namespace_uri, "http://www.w3.org/1999/xhtml")) return false;

    if (std.mem.eql(u8, command, "toggle-popover") or
        std.mem.eql(u8, command, "show-popover") or
        std.mem.eql(u8, command, "hide-popover"))
    {
        return true;
    }

    if (std.mem.eql(u8, element.tag_name, "dialog") and
        (std.mem.eql(u8, command, "close") or
            std.mem.eql(u8, command, "request-close") or
            std.mem.eql(u8, command, "show-modal")))
    {
        return true;
    }

    return false;
}

pub fn buttonIsSubmitButton(host: anytype, element_id: dom.NodeId) errors.Result(bool) {
    const state = try buttonTypeState(host, element_id);
    switch (state) {
        .submit => return true,
        .reset, .button => return false,
        .auto => {},
    }

    if (try host.domStore().hasAttribute(element_id, "command")) return false;
    if (try host.domStore().hasAttribute(element_id, "commandfor")) return false;

    const node = host.domStore().nodeAt(element_id) orelse return false;
    const parent_id = node.parent orelse return true;
    const parent = host.domStore().nodeAt(parent_id) orelse return false;
    return switch (parent.kind) {
        .element => |element| !std.mem.eql(u8, element.tag_name, "select"),
        else => true,
    };
}

fn elementSupportsClickProperty(host: anytype, element_id: dom.NodeId) errors.Result(bool) {
    const namespace_uri = host.domStore().namespaceUriForNode(element_id) orelse return false;
    return std.mem.eql(u8, namespace_uri, "http://www.w3.org/1999/xhtml");
}

pub fn popoverTargetActionValue(host: anytype, element_id: dom.NodeId) errors.Result([]const u8) {
    const action = (try host.domStore().getAttribute(element_id, "popovertargetaction")) orelse return "toggle";
    const trimmed = std.mem.trim(u8, action, " \t\r\n\x0c");
    if (trimmed.len == 0) return "toggle";
    if (std.ascii.eqlIgnoreCase(trimmed, "show")) return "show";
    if (std.ascii.eqlIgnoreCase(trimmed, "hide")) return "hide";
    return "toggle";
}

pub fn popoverTargetElement(host: anytype, element_id: dom.NodeId) errors.Result(?dom.NodeId) {
    if (!try elementSupportsPopoverTargetProperty(host, element_id)) return null;
    const tag_name = host.domStore().tagNameForNode(element_id) orelse return null;
    if (std.mem.eql(u8, tag_name, "button")) {
        if (try host.domStore().hasAttribute(element_id, "disabled")) return null;
        if (try elementIsSubmitControl(host, element_id)) {
            if (try elementFormOwner(host, element_id)) |_| {
                return null;
            }
        }
    } else {
        const input_type = (try host.domStore().getAttribute(element_id, "type")) orelse "text";
        if (!std.mem.eql(u8, input_type, "button")) {
            if (try elementFormOwner(host, element_id)) |_| {
                return null;
            }
        }
        if (try host.domStore().hasAttribute(element_id, "disabled")) return null;
    }

    const target_ref = (try host.domStore().getAttribute(element_id, "popovertarget")) orelse return null;
    const trimmed = std.mem.trim(u8, target_ref, " \t\r\n\x0c");
    if (trimmed.len == 0) return null;
    const target_id = host.domStore().findElementById(trimmed) orelse return null;
    const target_state = host.domStore().popoverStateForNode(target_id) orelse return null;
    if (target_state == .no_popover) return null;
    return target_id;
}

fn inputListElement(host: anytype, element_id: dom.NodeId) errors.Result(?dom.NodeId) {
    const tag_name = host.domStore().tagNameForNode(element_id) orelse return null;
    if (!std.ascii.eqlIgnoreCase(tag_name, "input")) return null;

    const list_ref = (try host.domStore().getAttribute(element_id, "list")) orelse return null;
    const trimmed = std.mem.trim(u8, list_ref, " \t\r\n\x0c");
    if (trimmed.len == 0) return null;

    const datalist_id = host.domStore().findElementById(trimmed) orelse return null;
    const datalist_tag = host.domStore().tagNameForNode(datalist_id) orelse return null;
    if (!std.mem.eql(u8, datalist_tag, "datalist")) return null;
    return datalist_id;
}

fn inputSizeValue(host: anytype, element_id: dom.NodeId) errors.Result(usize) {
    const attr = (try host.domStore().getAttribute(element_id, "size")) orelse return 20;
    const trimmed = std.mem.trim(u8, attr, " \t\r\n\x0c");
    if (trimmed.len == 0) return 20;
    const parsed = std.fmt.parseInt(i64, trimmed, 10) catch return 20;
    if (parsed <= 0) return 20;
    return std.math.cast(usize, parsed) orelse 20;
}

fn selectSizeValue(host: anytype, element_id: dom.NodeId) errors.Result(usize) {
    const attr = (try host.domStore().getAttribute(element_id, "size")) orelse return 0;
    const trimmed = std.mem.trim(u8, attr, " \t\r\n\x0c");
    if (trimmed.len == 0) return 0;
    return std.fmt.parseInt(usize, trimmed, 10) catch 0;
}

fn inputSizeFromValue(allocator: std.mem.Allocator, value: Value) errors.Result(usize) {
    const size = try tableCellSpanFromValue(allocator, value);
    return std.math.cast(usize, size) orelse error.ScriptRuntime;
}

fn textareaDimensionValue(host: anytype, element_id: dom.NodeId, attribute_name: []const u8, fallback: usize) errors.Result(usize) {
    const attr = (try host.domStore().getAttribute(element_id, attribute_name)) orelse return fallback;
    const trimmed = std.mem.trim(u8, attr, " \t\r\n\x0c");
    if (trimmed.len == 0) return fallback;
    const parsed = std.fmt.parseInt(usize, trimmed, 10) catch return fallback;
    return if (parsed == 0) fallback else parsed;
}

fn canvasDimensionValue(host: anytype, element_id: dom.NodeId, attribute_name: []const u8, fallback: usize) errors.Result(usize) {
    const attr = (try host.domStore().getAttribute(element_id, attribute_name)) orelse return fallback;
    const trimmed = std.mem.trim(u8, attr, " \t\r\n\x0c");
