}

fn cssLengthValue(text: []const u8) ?f64 {
    const trimmed = std.mem.trim(u8, text, " \t\r\n");
    if (trimmed.len == 0) return null;
    if (trimmed.len >= 2 and std.ascii.eqlIgnoreCase(trimmed[trimmed.len - 2 ..], "px")) {
        return std.fmt.parseFloat(f64, trimmed[0 .. trimmed.len - 2]) catch null;
    }
    return std.fmt.parseFloat(f64, trimmed) catch null;
}

fn inlineStyleLengthValue(
    allocator: std.mem.Allocator,
    host: anytype,
    element: dom.NodeId,
    property: []const u8,
) errors.Result(f64) {
    const text = try elementInlineStylePropertyValue(allocator, host, element, property);
    defer allocator.free(text);
    return cssLengthValue(text) orelse 0.0;
}

fn makeDomRectValue(allocator: std.mem.Allocator, host: anytype, element: dom.NodeId) errors.Result(Value) {
    const left = try inlineStyleLengthValue(allocator, host, element, "left");
    const top = try inlineStyleLengthValue(allocator, host, element, "top");
    const width = try inlineStyleLengthValue(allocator, host, element, "width");
    const height = try inlineStyleLengthValue(allocator, host, element, "height");

    const state = try allocator.create(DomRectState);
    state.* = .{
        .x = left,
        .y = top,
        .width = width,
        .height = height,
        .top = top,
        .right = left + width,
        .bottom = top + height,
        .left = left,
    };
    return .{ .dom_rect = state };
}

fn makeDomRectListValue(allocator: std.mem.Allocator, host: anytype, element: dom.NodeId) errors.Result(Value) {
    const left = try inlineStyleLengthValue(allocator, host, element, "left");
    const top = try inlineStyleLengthValue(allocator, host, element, "top");
    const width = try inlineStyleLengthValue(allocator, host, element, "width");
    const height = try inlineStyleLengthValue(allocator, host, element, "height");

    const state = try allocator.create(DomRectListState);
    state.* = .{
        .rect = .{
            .x = left,
            .y = top,
            .width = width,
            .height = height,
            .top = top,
            .right = left + width,
            .bottom = top + height,
            .left = left,
        },
    };
    return .{ .dom_rect_list = state };
}

fn makeSelectionValue(allocator: std.mem.Allocator, host: anytype) errors.Result(Value) {
    const selection = SelectionSnapshot{};
    if (host.domStore().documentSelectionCleared()) {
        return .{ .selection = selection };
    }
    const active_element = host.documentActiveElement();
    if (active_element) |element| {
        if (host.domStore().selectionStateForNode(element) catch null) |state| {
            const value = try host.domStore().valueForNode(allocator, element);
            defer allocator.free(value);
            const anchor_offset = switch (state.direction) {
                .backward => state.end,
                .forward, .none => state.start,
            };
            const focus_offset = switch (state.direction) {
                .backward => state.start,
                .forward, .none => state.end,
            };
            const selected_text = try allocator.dupe(u8, value[state.start..state.end]);
            return .{ .selection = .{
                .selected_text = selected_text,
                .range_count = 1,
                .is_collapsed = state.start == state.end,
                .anchor_node = element,
                .focus_node = element,
                .anchor_offset = anchor_offset,
                .focus_offset = focus_offset,
                .type_text = if (state.start == state.end) "Caret" else "Range",
            } };
        }
    }

    return .{ .selection = selection };
}

fn makeTextTrackValue(host: anytype, element: dom.NodeId) errors.Result(Value) {
    const state = try host.domStoreMut().ensureTextTrackState(element);
    return .{ .text_track = state };
}

fn mediaTextTrackListTrackIds(
    allocator: std.mem.Allocator,
    host: anytype,
    media: dom.NodeId,
) errors.Result([]dom.NodeId) {
    return try host.domStore().selectWithin(allocator, media, "track");
}

fn namespaceUriFromValue(allocator: std.mem.Allocator, value: Value) errors.Result(?[]const u8) {
    return switch (value) {
        .null_value, .undefined_value => null,
        else => {
            const text = try asString(allocator, value);
            if (text.len == 0) return null;
            return text;
        },
    };
}

fn makeAttributeValue(
    allocator: std.mem.Allocator,
    namespace_value: Value,
    qualified_name_value: Value,
) errors.Result(Value) {
    const namespace_uri = try namespaceUriFromValue(allocator, namespace_value);
    const qualified_name = try asString(allocator, qualified_name_value);
    if (qualified_name.len == 0) return error.ScriptRuntime;

    if (std.mem.indexOfScalar(u8, qualified_name, ':')) |colon| {
        if (colon == 0 or colon + 1 >= qualified_name.len) return error.ScriptRuntime;
        if (std.mem.indexOfScalarPos(u8, qualified_name, colon + 1, ':') != null) return error.ScriptRuntime;
        if (namespace_uri == null) return error.ScriptRuntime;
    }

    return try makeAttributeSnapshotValue(allocator, namespace_uri, qualified_name, "", null);
}

fn makeAttributeSnapshotValue(
    allocator: std.mem.Allocator,
    namespace_uri: ?[]const u8,
    name: []const u8,
    value: []const u8,
    owner_element: ?dom.NodeId,
) errors.Result(Value) {
    const state = try allocator.create(AttributeState);
    state.* = .{
        .namespace_uri = namespace_uri,
        .name = name,
        .value = value,
        .owner_element = owner_element,
    };
    return .{ .attribute = state };
}

fn attributeNameMatchesLocalName(attribute_name: []const u8, local_name: []const u8) bool {
    if (std.mem.eql(u8, attribute_name, local_name)) return true;
    if (std.mem.indexOfScalar(u8, attribute_name, ':')) |colon| {
        if (colon + 1 < attribute_name.len) {
            return std.mem.eql(u8, attribute_name[colon + 1 ..], local_name);
        }
    }
    return false;
}

fn attributeNameMatchesNamespaceLocalName(attribute_name: []const u8, namespace_uri: ?[]const u8, local_name: []const u8) bool {
    const has_colon = std.mem.indexOfScalar(u8, attribute_name, ':') != null;
    if (namespace_uri == null) {
        return !has_colon and std.mem.eql(u8, attribute_name, local_name);
    }
    if (!has_colon) return false;
    return attributeNameMatchesLocalName(attribute_name, local_name);
}

fn getAttributeNodeSnapshot(
    allocator: std.mem.Allocator,
    host: anytype,
    element: dom.NodeId,
    namespace_uri: ?[]const u8,
    local_name: []const u8,
) errors.Result(?Value) {
    const node = host.domStore().nodeAt(element) orelse return error.ScriptRuntime;
    switch (node.kind) {
        .element => |element_node| {
            for (element_node.attributes.items) |attribute| {
                if (!attributeNameMatchesNamespaceLocalName(attribute.name, namespace_uri, local_name)) continue;
                return try makeAttributeSnapshotValue(allocator, namespace_uri, attribute.name, attribute.value, element);
            }
            return null;
        },
        else => return error.ScriptRuntime,
    }
}

fn namedNodeMapCurrentValues(
    allocator: std.mem.Allocator,
    host: anytype,
    element: dom.NodeId,
) errors.Result([]Value) {
    const node = host.domStore().nodeAt(element) orelse return error.ScriptRuntime;
    switch (node.kind) {
        .element => |element_node| {
            var items = try allocator.alloc(Value, element_node.attributes.items.len);
            errdefer allocator.free(items);

            for (element_node.attributes.items, 0..) |attribute, index| {
                items[index] = try makeAttributeSnapshotValue(allocator, null, attribute.name, attribute.value, element);
            }

            return items;
        },
        else => return error.ScriptRuntime,
    }
}

fn makeCssRuleStyleDeclarationValue(
    allocator: std.mem.Allocator,
    host: anytype,
    kind: CssRuleStyleDeclarationKind,
    css_text: []const u8,
    parent_style_sheet: ?dom.NodeId,
    source_index: ?usize,
    writable: bool,
) errors.Result(Value) {
    const Host = @TypeOf(host);
    const host_state = try allocator.create(CssRuleStyleDeclarationState);
    errdefer allocator.destroy(host_state);
    host_state.* = .{
        .host = @ptrCast(host),
        .kind = kind,
        .css_text = css_text,
        .parent_style_sheet = parent_style_sheet,
        .source_index = source_index,
        .writable = writable,
    };

    const state = try allocator.create(StyleDeclarationState);
    errdefer allocator.destroy(state);
    state.* = .{
        .host = @ptrCast(host_state),
        .element = dom.NodeId.new(0, 0),
        .get_attribute_fn = struct {
            fn call(
                ptr: *anyopaque,
                node: dom.NodeId,
                name: []const u8,
                alloc: std.mem.Allocator,
            ) errors.Result(?[]const u8) {
                _ = node;
                const typed: *CssRuleStyleDeclarationState = @ptrCast(@alignCast(ptr));
                if (std.mem.eql(u8, name, "style")) {
                    const typed_host: Host = @ptrCast(@alignCast(typed.host));
                    if (try cssRuleStyleDeclarationLiveState(alloc, typed_host, typed)) |live| {
                        return live.css_text;
                    }
                    return typed.css_text;
                }
                return null;
            }
        }.call,
        .set_attribute_fn = struct {
            fn call(
                ptr: *anyopaque,
                node: dom.NodeId,
                name: []const u8,
                value: []const u8,
                alloc: std.mem.Allocator,
            ) errors.Result(void) {
                _ = node;
                const typed: *CssRuleStyleDeclarationState = @ptrCast(@alignCast(ptr));
                if (!std.mem.eql(u8, name, "style")) return error.ScriptRuntime;
                const typed_host: Host = @ptrCast(@alignCast(typed.host));
                try cssRuleStyleDeclarationApply(alloc, typed_host, typed, value);
                return;
            }
        }.call,
    };

    return .{ .style_declaration = state };
}

fn cssRuleStyleDeclarationText(source: []const u8) errors.Result([]const u8) {
    const block_start = try parseCssRuleBlockStart(source, 0);
    const block_end = try parseCssRuleBlockEnd(source, block_start + 1);
    return source[block_start + 1 .. block_end - 1];
}

fn styleDeclarationCurrentText(
    allocator: std.mem.Allocator,
    state: *StyleDeclarationState,
) errors.Result([]const u8) {
    const raw = try state.get_attribute_fn(state.host, state.element, "style", allocator);
    if (raw) |text| return allocator.dupe(u8, text);
    return allocator.dupe(u8, "");
}

fn styleDeclarationEntries(
    allocator: std.mem.Allocator,
    state: *StyleDeclarationState,
) errors.Result(std.ArrayList(StylePropertyEntry)) {
    const raw = try styleDeclarationCurrentText(allocator, state);
    defer allocator.free(raw);
    return try parseStyleDeclarations(allocator, raw);
}

fn styleDeclarationCssText(
    allocator: std.mem.Allocator,
    state: *StyleDeclarationState,
) errors.Result([]const u8) {
    var entries = try styleDeclarationEntries(allocator, state);
    defer freeStyleDeclarations(allocator, &entries);
    return try serializeStyleDeclarations(allocator, entries.items);
}

fn styleDeclarationLength(
    allocator: std.mem.Allocator,
    state: *StyleDeclarationState,
) errors.Result(usize) {
    var entries = try styleDeclarationEntries(allocator, state);
    defer freeStyleDeclarations(allocator, &entries);
    return entries.items.len;
}

fn styleDeclarationItem(
    allocator: std.mem.Allocator,
    state: *StyleDeclarationState,
    index: usize,
) errors.Result([]const u8) {
    var entries = try styleDeclarationEntries(allocator, state);
    defer freeStyleDeclarations(allocator, &entries);
    if (index >= entries.items.len) return allocator.dupe(u8, "");
    return allocator.dupe(u8, entries.items[index].name);
}

fn styleDeclarationGetPropertyValue(
    allocator: std.mem.Allocator,
    state: *StyleDeclarationState,
    property: []const u8,
) errors.Result([]const u8) {
    const name = try stylePropertyName(allocator, property);
    defer allocator.free(name);

    var entries = try styleDeclarationEntries(allocator, state);
    defer freeStyleDeclarations(allocator, &entries);
    for (entries.items) |entry| {
        if (std.mem.eql(u8, entry.name, name)) {
            return allocator.dupe(u8, entry.value);
        }
    }
    return allocator.dupe(u8, "");
}

fn styleDeclarationGetPropertyPriority(
    allocator: std.mem.Allocator,
    state: *StyleDeclarationState,
    property: []const u8,
) errors.Result([]const u8) {
    const name = try stylePropertyName(allocator, property);
    defer allocator.free(name);

    var entries = try styleDeclarationEntries(allocator, state);
    defer freeStyleDeclarations(allocator, &entries);
    for (entries.items) |entry| {
        if (std.mem.eql(u8, entry.name, name)) {
            if (entry.important) {
                return allocator.dupe(u8, "important");
            }
            return allocator.dupe(u8, "");
        }
    }
    return allocator.dupe(u8, "");
}

fn styleDeclarationSetCssText(
    allocator: std.mem.Allocator,
    state: *StyleDeclarationState,
    text: []const u8,
) errors.Result(void) {
    var entries = try parseStyleDeclarations(allocator, text);
    defer freeStyleDeclarations(allocator, &entries);
    const css_text = try serializeStyleDeclarations(allocator, entries.items);
    defer allocator.free(css_text);
    try state.set_attribute_fn(state.host, state.element, "style", css_text, allocator);
    return;
}

fn styleDeclarationSetProperty(
    allocator: std.mem.Allocator,
    state: *StyleDeclarationState,
    property: []const u8,
    value: []const u8,
    priority: ?[]const u8,
) errors.Result(void) {
    const name = try stylePropertyName(allocator, property);
    defer allocator.free(name);

    const parsed = try styleDeclarationValueFromText(allocator, value, priority);
    defer allocator.free(parsed.value);
    if (try styleValueHasTopLevelSemicolon(parsed.value)) return error.ScriptRuntime;

    var entries = try styleDeclarationEntries(allocator, state);
    defer freeStyleDeclarations(allocator, &entries);

    if (parsed.value.len == 0) {
        var index: usize = 0;
        while (index < entries.items.len) : (index += 1) {
            if (std.mem.eql(u8, entries.items[index].name, name)) {
                allocator.free(entries.items[index].name);
                allocator.free(entries.items[index].value);
                _ = entries.orderedRemove(index);
                break;
            }
        }
    } else {
        const value_copy = try allocator.dupe(u8, parsed.value);
        errdefer allocator.free(value_copy);
        var index: usize = 0;
        while (index < entries.items.len) : (index += 1) {
            if (std.mem.eql(u8, entries.items[index].name, name)) {
                allocator.free(entries.items[index].value);
                entries.items[index].value = value_copy;
                entries.items[index].important = parsed.important;
                break;
            }
        }

        if (index == entries.items.len) {
            const name_copy = try allocator.dupe(u8, name);
            errdefer allocator.free(name_copy);
            try entries.append(allocator, .{
                .name = name_copy,
                .value = value_copy,
                .important = parsed.important,
            });
        }
    }

    const css_text = try serializeStyleDeclarations(allocator, entries.items);
    defer allocator.free(css_text);
    try state.set_attribute_fn(state.host, state.element, "style", css_text, allocator);
    return;
}

fn styleDeclarationRemoveProperty(
    allocator: std.mem.Allocator,
    state: *StyleDeclarationState,
    property: []const u8,
) errors.Result([]const u8) {
    const name = try stylePropertyName(allocator, property);
    defer allocator.free(name);

    var entries = try styleDeclarationEntries(allocator, state);
    defer freeStyleDeclarations(allocator, &entries);

    var removed_value = try allocator.dupe(u8, "");
    errdefer allocator.free(removed_value);
    var index: usize = 0;
    while (index < entries.items.len) : (index += 1) {
        if (std.mem.eql(u8, entries.items[index].name, name)) {
            allocator.free(removed_value);
            removed_value = try allocator.dupe(u8, entries.items[index].value);
            allocator.free(entries.items[index].name);
            allocator.free(entries.items[index].value);
            _ = entries.orderedRemove(index);
            break;
        }
    }

    const css_text = try serializeStyleDeclarations(allocator, entries.items);
    defer allocator.free(css_text);
    try state.set_attribute_fn(state.host, state.element, "style", css_text, allocator);
    return removed_value;
}

fn freeStyleDeclarations(allocator: std.mem.Allocator, entries: *std.ArrayList(StylePropertyEntry)) void {
    for (entries.items) |entry| {
        allocator.free(entry.name);
        allocator.free(entry.value);
    }
    entries.deinit(allocator);
}

fn parseStyleDeclarations(
    allocator: std.mem.Allocator,
    text: []const u8,
) errors.Result(std.ArrayList(StylePropertyEntry)) {
    var entries: std.ArrayList(StylePropertyEntry) = .empty;
    errdefer freeStyleDeclarations(allocator, &entries);

    var part: std.ArrayList(u8) = .empty;
    defer part.deinit(allocator);

    var pos: usize = 0;
    var in_string: ?u8 = null;
    var paren_depth: usize = 0;
    while (pos < text.len) {
        const byte = text[pos];

        if (in_string) |quote| {
            try part.append(allocator, byte);
            if (byte == '\\') {
                if (pos + 1 >= text.len) return error.ScriptRuntime;
                pos += 1;
                try part.append(allocator, text[pos]);
            } else if (byte == quote) {
                in_string = null;
            }
            pos += 1;
            continue;
        }

        if (byte == '"' or byte == '\'') {
            in_string = byte;
            try part.append(allocator, byte);
            pos += 1;
            continue;
        }

        if (byte == '/' and pos + 1 < text.len and text[pos + 1] == '*') {
            pos = try skipCssComment(text, pos);
            continue;
        }

        if (byte == '(') {
            paren_depth += 1;
            try part.append(allocator, byte);
            pos += 1;
            continue;
        }

        if (byte == ')') {
            if (paren_depth == 0) return error.ScriptRuntime;
            paren_depth -= 1;
            try part.append(allocator, byte);
            pos += 1;
            continue;
        }

        if (byte == '{' or byte == '}') return error.ScriptRuntime;

        if (byte == ';' and paren_depth == 0) {
            try parseStyleDeclarationPart(allocator, part.items, &entries);
            part.clearRetainingCapacity();
            pos += 1;
            continue;
        }

        try part.append(allocator, byte);
        pos += 1;
    }

    if (in_string != null or paren_depth != 0) return error.ScriptRuntime;
    try parseStyleDeclarationPart(allocator, part.items, &entries);

    return entries;
}

fn parseStyleDeclarationPart(
    allocator: std.mem.Allocator,
    raw_part: []const u8,
    entries: *std.ArrayList(StylePropertyEntry),
) errors.Result(void) {
    const declaration = std.mem.trim(u8, raw_part, " \t\r\n\x0c");
    if (declaration.len == 0) return;

    const colon_index = std.mem.indexOfScalar(u8, declaration, ':') orelse return error.ScriptRuntime;
    const name_source = std.mem.trim(u8, declaration[0..colon_index], " \t\r\n\x0c");
    const value_source = std.mem.trim(u8, declaration[colon_index + 1 ..], " \t\r\n\x0c");
    const name = try stylePropertyName(allocator, name_source);
    errdefer allocator.free(name);
    const parsed_value = try styleDeclarationValueFromText(allocator, value_source, null);
    defer allocator.free(parsed_value.value);
    const value = try allocator.dupe(u8, parsed_value.value);
    errdefer allocator.free(value);

    var index: usize = 0;
    while (index < entries.items.len) : (index += 1) {
        if (std.mem.eql(u8, entries.items[index].name, name)) {
            allocator.free(entries.items[index].value);
            allocator.free(name);
            entries.items[index].value = value;
            entries.items[index].important = parsed_value.important;
            break;
        }
    }

    if (index == entries.items.len) {
        try entries.append(allocator, .{
            .name = name,
            .value = value,
            .important = parsed_value.important,
        });
    }
}

fn styleValueHasTopLevelSemicolon(text: []const u8) errors.Result(bool) {
    var pos: usize = 0;
    var in_string: ?u8 = null;
    var paren_depth: usize = 0;
    while (pos < text.len) {
        const byte = text[pos];

        if (in_string) |quote| {
            if (byte == '\\') {
                if (pos + 1 >= text.len) return error.ScriptRuntime;
                pos += 2;
                continue;
            }
            if (byte == quote) in_string = null;
            pos += 1;
            continue;
        }

        if (byte == '"' or byte == '\'') {
            in_string = byte;
            pos += 1;
            continue;
        }

        if (byte == '/' and pos + 1 < text.len and text[pos + 1] == '*') {
            pos = try skipCssComment(text, pos);
            continue;
        }

        if (byte == '(') {
            paren_depth += 1;
            pos += 1;
            continue;
        }

        if (byte == ')') {
            if (paren_depth == 0) return error.ScriptRuntime;
            paren_depth -= 1;
            pos += 1;
            continue;
        }

        if (byte == ';' and paren_depth == 0) return true;
        pos += 1;
    }

    if (in_string != null or paren_depth != 0) return error.ScriptRuntime;
    return false;
}

fn serializeStyleDeclarations(
    allocator: std.mem.Allocator,
    entries: []const StylePropertyEntry,
) errors.Result([]const u8) {
    var out: std.ArrayList(u8) = .empty;
    errdefer out.deinit(allocator);

    for (entries, 0..) |entry, index| {
        if (index > 0) {
            try out.appendSlice(allocator, " ");
        }
        try out.appendSlice(allocator, entry.name);
        try out.appendSlice(allocator, ": ");
        try out.appendSlice(allocator, entry.value);
        if (entry.important) {
            try out.appendSlice(allocator, " !important");
        }
        try out.append(allocator, ';');
    }

    return try allocator.dupe(u8, out.items);
}

fn stripCssComments(
    allocator: std.mem.Allocator,
    text: []const u8,
) errors.Result([]const u8) {
    var out: std.ArrayList(u8) = .empty;
    errdefer out.deinit(allocator);

    var index: usize = 0;
    while (index < text.len) {
        if (index + 1 < text.len and text[index] == '/' and text[index + 1] == '*') {
            const rest = text[index + 2 ..];
            const comment_end = std.mem.indexOf(u8, rest, "*/") orelse return error.ScriptRuntime;
            index += 2 + comment_end + 2;
            continue;
        }

        try out.append(allocator, text[index]);
        index += 1;
    }

    return try allocator.dupe(u8, out.items);
}

fn styleDeclarationValueFromText(
    allocator: std.mem.Allocator,
    text: []const u8,
    priority: ?[]const u8,
) errors.Result(StyleValueEntry) {
    const trimmed_priority = if (priority) |text_value|
        std.mem.trim(u8, text_value, " \t\r\n\x0c")
    else
        "";
    if (trimmed_priority.len != 0 and !std.ascii.eqlIgnoreCase(trimmed_priority, "important")) {
        return error.ScriptRuntime;
    }

    const trimmed_value = std.mem.trim(u8, text, " \t\r\n\x0c");
    var value_text = trimmed_value;
    var important = trimmed_priority.len != 0;
    if (endsWithImportant(trimmed_value)) {
        important = true;
        value_text = std.mem.trimRight(u8, trimmed_value[0 .. trimmed_value.len - "!important".len], " \t\r\n\x0c");
    }

    return .{
        .value = try allocator.dupe(u8, value_text),
        .important = important,
    };
}

fn endsWithImportant(text: []const u8) bool {
    const suffix = "!important";
    if (text.len < suffix.len) return false;
    return std.ascii.eqlIgnoreCase(text[text.len - suffix.len ..], suffix);
}

fn stylePropertyName(
    allocator: std.mem.Allocator,
    text: []const u8,
) errors.Result([]const u8) {
    const trimmed = std.mem.trim(u8, text, " \t\r\n\x0c");
    if (trimmed.len == 0) return error.ScriptRuntime;
    if (std.mem.eql(u8, trimmed, "cssFloat")) return allocator.dupe(u8, "float");

    const has_hyphen = std.mem.indexOfScalar(u8, trimmed, '-') != null;
    var has_lowercase = false;
    for (trimmed) |byte| {
        if (std.ascii.isLower(byte)) {
            has_lowercase = true;
            break;
        }
    }
    const camel_case = !has_hyphen and has_lowercase;

    var out: std.ArrayList(u8) = .empty;
    errdefer out.deinit(allocator);

    for (trimmed, 0..) |byte, index| {
        switch (byte) {
            'A'...'Z' => {
                if (camel_case and index > 0) {
                    try out.append(allocator, '-');
                }
                try out.append(allocator, std.ascii.toLower(byte));
            },
            'a'...'z', '0'...'9', '-', '_' => try out.append(allocator, std.ascii.toLower(byte)),
            else => return error.ScriptRuntime,
        }
    }

    if (out.items.len == 0) return error.ScriptRuntime;
    return try allocator.dupe(u8, out.items);
}

fn historyDeltaFromExpr(
    allocator: std.mem.Allocator,
    host: anytype,
    bindings: []const Binding,
    expr: *Expr,
) errors.Result(isize) {
    const value = try evalExpr(allocator, host, bindings, expr);
    return try historyDeltaFromValue(allocator, value);
}

fn historyDeltaFromValue(allocator: std.mem.Allocator, value: Value) errors.Result(isize) {
    return switch (value) {
        .number => |number| blk: {
            if (!std.math.isFinite(number)) return error.ScriptRuntime;
            if (std.math.round(number) != number) return error.ScriptRuntime;
            const as_i64 = @as(i64, @intFromFloat(number));
            break :blk std.math.cast(isize, as_i64) orelse error.ScriptRuntime;
        },
        else => blk: {
            const text = try asString(allocator, value);
            const trimmed = std.mem.trim(u8, text, " \t\r\n");
            break :blk std.fmt.parseInt(isize, trimmed, 10) catch error.ScriptRuntime;
        },
    };
}

fn lengthLimitFromValue(allocator: std.mem.Allocator, value: Value) errors.Result(isize) {
    return historyDeltaFromValue(allocator, value);
}

fn textLengthLimitValue(host: anytype, element_id: dom.NodeId, attribute_name: []const u8) errors.Result(isize) {
    const text = (try host.domStore().getAttribute(element_id, attribute_name)) orelse return -1;
    const trimmed = std.mem.trim(u8, text, " \t\r\n\x0c");
    if (trimmed.len == 0) return -1;
    return std.fmt.parseInt(isize, trimmed, 10) catch -1;
}

fn scrollCoordinate(value: Value, method: []const u8) errors.Result(i64) {
    return switch (value) {
        .number => |number| blk: {
            if (!std.math.isFinite(number)) return error.ScriptRuntime;
            if (std.math.round(number) != number) return error.ScriptRuntime;
            const min = @as(f64, @floatFromInt(std.math.minInt(i64)));
            const max = @as(f64, @floatFromInt(std.math.maxInt(i64)));
            if (number < min or number > max) return error.ScriptRuntime;
            break :blk @as(i64, @intFromFloat(number));
        },
        .string => |text| std.fmt.parseInt(i64, text, 10) catch {
            _ = method;
            return error.ScriptRuntime;
        },
        else => {
            _ = method;
            return error.ScriptRuntime;
        },
    };
}

fn historyStateFromValue(allocator: std.mem.Allocator, value: Value) errors.Result(?[]const u8) {
    return switch (value) {
        .undefined_value, .null_value => null,
        else => try asString(allocator, value),
    };
}

fn selectionIndexFromValue(allocator: std.mem.Allocator, value: Value) errors.Result(usize) {
    return switch (value) {
        .number => |number| blk: {
            if (!std.math.isFinite(number)) return error.ScriptRuntime;
            if (std.math.round(number) != number) return error.ScriptRuntime;
            if (number < 0) return error.ScriptRuntime;
            const max_index: f64 = @floatFromInt(std.math.maxInt(usize));
            if (number > max_index) return error.ScriptRuntime;
            break :blk @as(usize, @intFromFloat(number));
        },
        else => blk: {
            const text = try asString(allocator, value);
            const trimmed = std.mem.trim(u8, text, " \t\r\n");
            if (trimmed.len == 0) return error.ScriptRuntime;
            const parsed = std.fmt.parseInt(i64, trimmed, 10) catch return error.ScriptRuntime;
            if (parsed < 0) return error.ScriptRuntime;
            break :blk @as(usize, @intCast(parsed));
        },
    };
}

fn tabIndexFromValue(allocator: std.mem.Allocator, value: Value) errors.Result(i64) {
    return switch (value) {
        .number => |number| blk: {
            if (!std.math.isFinite(number)) return error.ScriptRuntime;
            if (std.math.round(number) != number) return error.ScriptRuntime;
            const min_index: f64 = @floatFromInt(std.math.minInt(i64));
            const max_index: f64 = @floatFromInt(std.math.maxInt(i64));
            if (number < min_index or number > max_index) return error.ScriptRuntime;
            break :blk @as(i64, @intFromFloat(number));
        },
        else => blk: {
            const text = try asString(allocator, value);
            const trimmed = std.mem.trim(u8, text, " \t\r\n");
            if (trimmed.len == 0) return error.ScriptRuntime;
            break :blk std.fmt.parseInt(i64, trimmed, 10) catch error.ScriptRuntime;
        },
    };
}

fn selectionDirectionFromString(text: []const u8) ?dom.SelectionDirection {
    if (std.ascii.eqlIgnoreCase(text, "forward")) return .forward;
    if (std.ascii.eqlIgnoreCase(text, "backward")) return .backward;
    if (std.ascii.eqlIgnoreCase(text, "none")) return .none;
    return null;
}

fn selectionDirectionName(direction: dom.SelectionDirection) []const u8 {
    return switch (direction) {
        .forward => "forward",
        .backward => "backward",
        .none => "none",
    };
}

fn selectionModeFromString(text: []const u8) ?dom.RangeTextSelectionMode {
    if (std.ascii.eqlIgnoreCase(text, "preserve")) return .preserve;
    if (std.ascii.eqlIgnoreCase(text, "select")) return .select;
    if (std.ascii.eqlIgnoreCase(text, "start")) return .start;
    if (std.ascii.eqlIgnoreCase(text, "end")) return .end;
    return null;
}

fn timerDelayFromExpr(
    allocator: std.mem.Allocator,
    host: anytype,
    bindings: []const Binding,
    expr: *Expr,
) errors.Result(i64) {
    const value = try evalExpr(allocator, host, bindings, expr);
    return try timerDelayFromValue(allocator, value);
}

fn timerDelayFromValue(allocator: std.mem.Allocator, value: Value) errors.Result(i64) {
    return switch (value) {
        .number => |number| blk: {
            if (!std.math.isFinite(number)) return error.ScriptRuntime;
            if (std.math.round(number) != number) return error.ScriptRuntime;
            const min = @as(f64, @floatFromInt(std.math.minInt(i64)));
            const max = @as(f64, @floatFromInt(std.math.maxInt(i64)));
            if (number < min or number > max) return error.ScriptRuntime;
            const delay = @as(i64, @intFromFloat(number));
            break :blk if (delay < 0) 0 else delay;
        },
        else => blk: {
            const text = try asString(allocator, value);
            const trimmed = std.mem.trim(u8, text, " \t\r\n");
            const parsed = std.fmt.parseInt(i64, trimmed, 10) catch return error.ScriptRuntime;
            break :blk if (parsed < 0) 0 else parsed;
        },
    };
}

fn numberFromValue(allocator: std.mem.Allocator, value: Value) errors.Result(f64) {
    return switch (value) {
        .number => |number| number,
        .boolean => |flag| if (flag) 1.0 else 0.0,
        .null_value => 0.0,
        .undefined_value => std.math.nan(f64),
        else => blk: {
            const text = try asString(allocator, value);
            const trimmed = std.mem.trim(u8, text, " \t\r\n");
            if (trimmed.len == 0) break :blk 0.0;
            break :blk std.fmt.parseFloat(f64, trimmed) catch std.math.nan(f64);
        },
    };
}

fn parseFloatingPointAttributeValue(value: ?[]const u8) ?f64 {
    const text = value orelse return null;
    const trimmed = std.mem.trim(u8, text, " \t\r\n\x0c");
    if (trimmed.len == 0) return null;
    return std.fmt.parseFloat(f64, trimmed) catch null;
}

fn clampFloatValue(value: f64, min: f64, max: f64) f64 {
    if (value < min) return min;
    if (value > max) return max;
    return value;
}

const MeterRangeState = struct {
    min: f64,
    max: f64,
};

fn progressMaxValue(host: anytype, element: dom.NodeId) errors.Result(f64) {
    const value = parseFloatingPointAttributeValue(try host.domStore().getAttribute(element, "max"));
    if (value) |parsed| {
        if (std.math.isFinite(parsed) and parsed > 0) return parsed;
    }
    return 1.0;
}

fn progressValueForNode(host: anytype, element: dom.NodeId) errors.Result(?f64) {
    const value_attr = try host.domStore().getAttribute(element, "value");
    if (value_attr == null) return null;
    const parsed = parseFloatingPointAttributeValue(value_attr) orelse 0.0;
    const max = try progressMaxValue(host, element);
    return clampFloatValue(if (std.math.isFinite(parsed) and parsed > 0) parsed else 0.0, 0.0, max);
}

fn meterRangeState(host: anytype, element: dom.NodeId) errors.Result(MeterRangeState) {
    const min_value = parseFloatingPointAttributeValue(try host.domStore().getAttribute(element, "min"));
    const min = if (min_value) |parsed| if (std.math.isFinite(parsed)) parsed else 0.0 else 0.0;
    const max_candidate_value = parseFloatingPointAttributeValue(try host.domStore().getAttribute(element, "max"));
    const max_candidate = if (max_candidate_value) |parsed| if (std.math.isFinite(parsed)) parsed else 1.0 else 1.0;
    const max = if (max_candidate >= min) max_candidate else min;
    return .{ .min = min, .max = max };
}

fn meterValueForNode(host: anytype, element: dom.NodeId) errors.Result(f64) {
    const range = try meterRangeState(host, element);
    const value_candidate = parseFloatingPointAttributeValue(try host.domStore().getAttribute(element, "value"));
    const value = if (value_candidate) |parsed| if (std.math.isFinite(parsed)) parsed else 0.0 else 0.0;
    return clampFloatValue(value, range.min, range.max);
}

fn meterLowValue(host: anytype, element: dom.NodeId) errors.Result(f64) {
    const range = try meterRangeState(host, element);
    const low_candidate = parseFloatingPointAttributeValue(try host.domStore().getAttribute(element, "low"));
    const value = if (low_candidate) |parsed| if (std.math.isFinite(parsed)) parsed else range.min else range.min;
    return clampFloatValue(value, range.min, range.max);
}

fn meterHighValue(host: anytype, element: dom.NodeId) errors.Result(f64) {
    const range = try meterRangeState(host, element);
    const low = try meterLowValue(host, element);
    const high_candidate = parseFloatingPointAttributeValue(try host.domStore().getAttribute(element, "high"));
    var value = if (high_candidate) |parsed| if (std.math.isFinite(parsed)) parsed else range.max else range.max;
    if (value < low) value = low;
    if (value > range.max) value = range.max;
    return value;
}

fn meterOptimumValue(host: anytype, element: dom.NodeId) errors.Result(f64) {
    const range = try meterRangeState(host, element);
    const optimum_candidate = parseFloatingPointAttributeValue(try host.domStore().getAttribute(element, "optimum"));
    const value = if (optimum_candidate) |parsed| if (std.math.isFinite(parsed)) parsed else (range.min + range.max) / 2.0 else (range.min + range.max) / 2.0;
    return clampFloatValue(value, range.min, range.max);
}

fn timerIdFromExpr(
    allocator: std.mem.Allocator,
    host: anytype,
    bindings: []const Binding,
    expr: *Expr,
) errors.Result(?u64) {
    const value = try evalExpr(allocator, host, bindings, expr);
    return timerIdFromValue(allocator, value);
}

fn timerIdFromValue(allocator: std.mem.Allocator, value: Value) errors.Result(?u64) {
    return switch (value) {
        .number => |number| blk: {
            if (!std.math.isFinite(number)) break :blk null;
            if (std.math.round(number) != number) break :blk null;
            const min = @as(f64, @floatFromInt(@as(i64, 0)));
            const max = @as(f64, @floatFromInt(std.math.maxInt(u64)));
            if (number < min or number > max) break :blk null;
            const id = @as(u64, @intFromFloat(number));
            break :blk id;
        },
        else => blk: {
            const text = try asString(allocator, value);
            const trimmed = std.mem.trim(u8, text, " \t\r\n");
            const parsed = std.fmt.parseInt(i64, trimmed, 10) catch return null;
            if (parsed < 0) break :blk null;
            break :blk @as(u64, @intCast(parsed));
        },
    };
}

