fn tokenListTokens(
    allocator: std.mem.Allocator,
    host: anytype,
    element: dom.NodeId,
    attribute_name: []const u8,
) errors.Result(std.ArrayList([]const u8)) {
    const token_value = (try host.domStore().getAttribute(element, attribute_name)) orelse "";
    return tokenListTokensFromText(allocator, token_value);
}

fn tokenListTokensFromText(
    allocator: std.mem.Allocator,
    text: []const u8,
) errors.Result(std.ArrayList([]const u8)) {
    var tokens: std.ArrayList([]const u8) = .empty;
    errdefer tokens.deinit(allocator);

    var iter = std.mem.tokenizeAny(u8, text, " \t\r\n\x0c");
    while (iter.next()) |candidate| {
        if (classListContains(tokens.items, candidate)) continue;
        try tokens.append(allocator, candidate);
    }

    return tokens;
}

fn tokenListValue(
    allocator: std.mem.Allocator,
    tokens: []const []const u8,
) errors.Result([]const u8) {
    var joined: std.ArrayList(u8) = .empty;
    errdefer joined.deinit(allocator);

    for (tokens, 0..) |token, index| {
        if (index > 0) {
            try joined.appendSlice(allocator, " ");
        }
        try joined.appendSlice(allocator, token);
    }

    return try allocator.dupe(u8, joined.items);
}

fn classListContains(tokens: []const []const u8, token: []const u8) bool {
    for (tokens) |candidate| {
        if (std.mem.eql(u8, candidate, token)) return true;
    }
    return false;
}

fn relListSupportsToken(token: []const u8) bool {
    const supported_tokens = [_][]const u8{
        "alternate",
        "author",
        "bookmark",
        "canonical",
        "dns-prefetch",
        "external",
        "help",
        "icon",
        "license",
        "manifest",
        "modulepreload",
        "next",
        "nofollow",
        "noopener",
        "noreferrer",
        "opener",
        "pingback",
        "preconnect",
        "prefetch",
        "preload",
        "prerender",
        "prev",
        "search",
        "stylesheet",
        "tag",
    };
    for (supported_tokens) |candidate| {
        if (std.ascii.eqlIgnoreCase(candidate, token)) return true;
    }
    return false;
}

fn formRelListSupportsToken(token: []const u8) bool {
    const supported_tokens = [_][]const u8{
        "noreferrer",
        "noopener",
        "opener",
    };
    for (supported_tokens) |candidate| {
        if (std.ascii.eqlIgnoreCase(candidate, token)) return true;
    }
    return false;
}

fn relListSupportsTokenForElement(
    allocator: std.mem.Allocator,
    host: anytype,
    element_id: dom.NodeId,
    token: []const u8,
) errors.Result(bool) {
    _ = allocator;
    const tag_name = host.domStore().tagNameForNode(element_id) orelse return false;
    if (std.ascii.eqlIgnoreCase(tag_name, "form")) {
        return formRelListSupportsToken(token);
    }
    return relListSupportsToken(token);
}

fn blockingListSupportsToken(token: []const u8) bool {
    return std.ascii.eqlIgnoreCase(token, "render");
}

fn controlsListSupportsToken(token: []const u8) bool {
    const supported_tokens = [_][]const u8{
        "nodownload",
        "nofullscreen",
        "noremoteplayback",
    };
    for (supported_tokens) |candidate| {
        if (std.ascii.eqlIgnoreCase(candidate, token)) return true;
    }
    return false;
}

fn sandboxListSupportsToken(token: []const u8) bool {
    const supported_tokens = [_][]const u8{
        "allow-downloads",
        "allow-forms",
        "allow-modals",
        "allow-orientation-lock",
        "allow-pointer-lock",
        "allow-popups",
        "allow-popups-to-escape-sandbox",
        "allow-presentation",
        "allow-same-origin",
        "allow-scripts",
        "allow-storage-access-by-user-activation",
        "allow-top-navigation",
        "allow-top-navigation-by-user-activation",
        "allow-top-navigation-to-custom-protocols",
    };
    for (supported_tokens) |candidate| {
        if (std.ascii.eqlIgnoreCase(candidate, token)) return true;
    }
    return false;
}

fn validateClassListToken(
    allocator: std.mem.Allocator,
    value: Value,
) errors.Result([]const u8) {
    const token = try asString(allocator, value);
    const trimmed = std.mem.trim(u8, token, " \t\r\n\x0c");
    if (trimmed.len == 0 or trimmed.len != token.len) return error.ScriptRuntime;
    for (trimmed) |byte| {
        if (isWhitespaceByte(byte)) return error.ScriptRuntime;
    }
    return trimmed;
}

